var PREDEFINED_NATIONS = [
  { name: "Abkhaz", adjective: "Abkhaz", graphic_str: "abkhazia", legend: "Ancestors of Abkhazians have lived in the western Caucasus since time immemorial. Short periods of independence alternated with domination by the Greeks, Romans, Byzantines, Turks, Russians and Georgians." },
  { name: "Abyssinian", adjective: "Abyssinian", graphic_str: "ethiopia_old", legend: "Abyssinians - also known as Habesha or Ethiopians - are a Semitic people who ruled historical states in the Horn of Africa, the most prominent being the Aksumite Kingdom and the Ethiopian Empire." },
  { name: "Acadian", adjective: "Acadian", graphic_str: "acadia", legend: "Acadia was first founded in 1604 as the first French colony in North America. It was soon caught in the crossfire of French-English wars, leading Acadia to change hands frequently." },
  { name: "Acehnese", adjective: "Acehnese", graphic_str: "aceh", legend: "The Sultanate of Aceh located on the western tip of the island of Sumatra was a regional power in the 16th and 17th centuries, controlling much of the trade through the Strait of Malacca. Aceh was subjugated by the Dutch in the bloody Aceh War of 1873-1903." },
  { name: "Acrean", adjective: "Acrean", graphic_str: "acre", legend: "Acre is the westernmost state of Brazil. The region was part of Bolivia until 1899, when Brazilian settlers revolted and declared an Independent State of Acre." },
  { name: "Afghani", adjective: "Afghani", graphic_str: "afghanistan", legend: "Afghanistan, often called the crossroads of Central Asia, has had a very turbulent history. Through the ages, the country has been occupied by many forces including the Persian Empire, Genghis Khan and Alexander the Great." },
  { name: "African", adjective: "African", graphic_str: "africa", legend: "Africa: the cradle of humanity. It is the world's second largest continent and also its second most populous." },
  { name: "Ainu", adjective: "Ainu", graphic_str: "ainu", legend: "The Ainu are the indigenous people of northern Japan, the Kuril islands, Sakhalin, and the southern part of the Kamchatka peninsula." },
  { name: "Akwe", adjective: "Akwe", graphic_str: "akwe", legend: "The Akwe are also known by three different tribal names in Portuguese, Xavante, Xakriaba and Xerente. They have a patrilineal clan system and live in Mato Grosso and Tocantins states of Brazil, though they have been forced to move by Brazilians several times through their history." },
  { name: "Ålander", adjective: "Ålander", graphic_str: "aland", legend: "Åland is an archipelago in the Baltic Sea, located between Sweden and Finland. The islands' inhabitants are Swedish speaking, but Åland is an autonomous province in Finland, a status that was reached in 1921 after a long period in which the islands were contested between Sweden and Finland." },
  { name: "Albanian", adjective: "Albanian", graphic_str: "albania", legend: "Inhabitants of the Balkan peninsula, the ethnic origins of the Albanians are uncertain, though it has been suggested they descend from the Illyrians of Classical Antiquity. Albania changed hands several times during its history." },
  { name: "Aleut", adjective: "Aleut", graphic_str: "aleut", legend: "The Unangan, or Aleut, lived in permanent subterranean homes in their hunting and fishing villages. They lived in the Aleutian islands for thousands of years prior to European contact." },
  { name: "Algerian", adjective: "Algerian", graphic_str: "algeria", legend: "Algeria is an Arabic nation in North Africa. It is historically inhabited by the Berber people." },
  { name: "Alsatian", adjective: "Alsatian", graphic_str: "alsace", legend: "Alsace is a region in Europe, on the border of France and Germany. During the Middle Ages Alsace was part of the Holy Roman Empire, and consisted of several quite wealthy city-states." },
  { name: "Amazigh", adjective: "Amazigh", graphic_str: "amazigh", legend: "The Amazigh civilization is one of the oldest in the Mediterranean Basin, co-existing with ancient Egypt. The Imazighen people, which means \"free men \", are sturdy and strong but cheerful and generous with a great consideration for family and tribe." },
  { name: "Amazonian", adjective: "Amazonian", graphic_str: "amazon", legend: "The Amazons are a fictional nation of women warriors which appear in Classical Greek writing and art. Authors have located them in the Ukraine, Asia Minor, or Libya." },
  { name: "American", adjective: "American", graphic_str: "usa", legend: "The United States of America achieved its independence from Great Britain after a revolution in 1776-1783 CE. Its constitution was proclaimed in 1789, making the country one of the first modern representative republics." },
  { name: "Andalusi", adjective: "Andalusi", graphic_str: "almohad", legend: "Al-Andalus was the parts of the Iberian peninsula that was under Muslim control during the Middle Ages. Muslim Andalusians are noted for their splendid architectural heritage." },
  { name: "Andorran", adjective: "Andorran", graphic_str: "andorra", legend: "Andorra is a small country in the eastern Pyrenees. In 1278, a dispute between the bishop of Urgell and the Count of Foix ended with an agreement to share the sovereignty of Andorra." },
  { name: "Angolan", adjective: "Angolan", graphic_str: "angola", legend: "When the Portuguese arrived in Angola in the 15th century the region was controlled by several Bantu kingdoms. Angola became an important source of slave traders until well into the 19th century." },
  { name: "Anhaltian", adjective: "Anhaltian", graphic_str: "anhalt", legend: "Anhalt was a German state. Initially a county, it was split from Saxony in 1212." },
  { name: "Animal Kingdom", adjective: "AnimalKingdom", graphic_str: "animals", legend: "Before civilization claimed the lands, ancient man had to survive the wilderness with all kinds of dangerous animals." },
  { name: "Anishinaabe", adjective: "Anishinaabe", graphic_str: "anishinaabe", legend: "The Anishinaabeg are a group of closely related Native American tribes in the North American Great Lakes region, including the Ottawa, Ojibwe, Algonkin and Potawatomi. They speak Algonquian languages." },
  { name: "Antarctican", adjective: "Antarctican", graphic_str: "antarctica", legend: "Independent South Pole, land of penguins." },
  { name: "Antiguan and Barbudan", adjective: "AntiguanandBarbudan", graphic_str: "antigua_and_barbuda", legend: "Antigua and Barbuda is a country in the Eastern Caribbean consisting of the two eponymous islands as well as a number of smaller islets. The country has been independent from the United Kingdom since 1981." },
  { name: "Antillean", adjective: "Antillean", graphic_str: "netherlands_antilles", legend: "The islands of Aruba, Bonaire, Curacao, Saba, Saint Martin and Saint Eustatius were colonized by the Dutch in the 17th century. Their population is of mixed European, African and Latin American heritage." },
  { name: "Apache", adjective: "Apache", graphic_str: "apache", legend: "The Apaches are a group of Athabascan speaking Indian tribes living in Arizona, New Mexico and Oklahoma. Apache groups include the Western, Chiricahua, Mescalero, Jicarilla, Lipan and Plains Apache." },
  { name: "Arab", adjective: "Arab", graphic_str: "arab", legend: "The Arab/Islamic civilization of 622 to 1495 CE." },
  { name: "Aragonese", adjective: "Aragonese", graphic_str: "aragon", legend: "Aragon was formed as a Frankish county and was elevated to a kingdom in the 11th century. It expanded its territory southwards during the reconquista and subsequently managed to control a large part of the Mediterranean." },
  { name: "Aramean", adjective: "Aramean", graphic_str: "aram", legend: "According to legend, the Aramean people are the descendants of Aram, the grandson of Noah." },
  { name: "Argentine", adjective: "Argentine", graphic_str: "argentina", legend: "Argentina is located on the south-eastern coast of South America. Since independence from Spain in 1816, it has been plagued by several internal and external conflicts." },
  { name: "Armenian", adjective: "Armenian", graphic_str: "armenia", legend: "According to legend, the Armenian people are the descendants of Haik - the great-great-grandson of Noah. The modern Republic of Armenia gained independence from the Soviet Union in 1991." },
  { name: "Ashanti", adjective: "Ashanti", graphic_str: "ashanti", legend: "The Ashanti were an ancient kingdom in a region that is currently a part of Ghana. The first Ashanti kingdom was founded in the 11th century." },
  { name: "Assamese", adjective: "Assamese", graphic_str: "assam", legend: "The Assam (Ahom) kingdom was founded in 1228 on the southeastern foothills of the Himalayas by a group of Shan people emigrating from what is today northeastern Burma. The Assamese kings famously defeated several expeditions by the mighty Mughal Empire, effectively halting the Mughals' eastward expansion." },
  { name: "Assyrian", adjective: "Assyrian", graphic_str: "assyria", legend: "Assyria was an empire in northern Mesopotamia, named after its capital Ashur." },
  { name: "Asturian", adjective: "Asturian", graphic_str: "asturias", legend: "The Astures were a Celtic people which occupied most of the northern coast of Spain. They battled against the Roman Empire until their defeat by Caesar Augustus' legions between 29 and 19 BCE." },
  { name: "Atlantean", adjective: "Atlantean", graphic_str: "atlantis", legend: "The mythical continent of Atlantis" },
  { name: "Australian", adjective: "Australian", graphic_str: "australia", legend: "Australia was founded as a British penal colony in 1788 CE. Originally comprising several colonies (New South Wales, Victoria, Queensland, South Australia, Western Australia and Tasmania) it became a single country in 1902." },
  { name: "Australian Aboriginal", adjective: "AustralianAboriginal", graphic_str: "aborigines", legend: "Australian Aborigines is a collective term for the original inhabitants of the Australian continent. Aborigines from different parts of Australia refer to themselves with different names, including Koori, Yamaji, Nunga, and Murri." },
  { name: "Austrian", adjective: "Austrian", graphic_str: "austria", legend: "The origins of Austria date back to the time of the Roman Empire when a Celtic kingdom was conquered by the Romans in approximately 15 BCE, and later became Noricum, a Roman province, in the mid 1st century CE - an area which mostly encloses today's Austria. In 788 CE, the Frankish king Charlemagne conquered the area, and introduced Christianity." },
  { name: "Avar", adjective: "Avar", graphic_str: "avar", legend: "The Avars or Eurasian Avars were an ancient nomadic confederation of mixed origin. The dominant language of this group was presumably Proto-Bulgarian within the Turkic Oghuz language subgroup, but the true origin of the Avars is unknown." },
  { name: "Aymara", adjective: "Aymara", graphic_str: "aymara", legend: "After the collapse of the Tiwanaku civilization in the Andes, their heirs reorganized into a set of culturally close Aymara kingdoms that thrived around the Titicaca lake until they were conquered by the Incas." },
  { name: "Azeri", adjective: "Azeri", graphic_str: "azerbaijan", legend: "The Azeris are the people of Azerbaijan. The territory of modern Azerbaijan was the scene of rises and falls of different ancient states of the Caucasus region." },
  { name: "Aztec", adjective: "Aztec", graphic_str: "aztec", legend: "The Azteca, a Nahuatl speaking people from the Sonoran desert, seized control of the Toltec-derived civilizations of Central Mexico during the 15th century, reviving the practice of human sacrifice. They were conquered by the Spanish under Cortés in 1521." },
  { name: "Babylonian", adjective: "Babylonian", graphic_str: "babylon", legend: "Babylon was the dominant city of Mesopotamia from the 18th to 7th centuries BCE under a succession of peoples including Amorites, Kassites, Assyrians, and Chaldeans." },
  { name: "Badian", adjective: "Badian", graphic_str: "baden", legend: "Baden was a country in Swabia, in southwestern Germany. After World War II it was merged with Wuerttemberg and Hohenzollern to form the land of Baden-Wuerttemberg." },
  { name: "Bahamian", adjective: "Bahamian", graphic_str: "bahamas", legend: "The Bahamas are an island group in North America. It was somewhere in the Bahamas that Columbus first set foot on American soil." },
  { name: "Bahraini", adjective: "Bahraini", graphic_str: "bahrain", legend: "Bahrain is an island country in the Persian Gulf and the smallest country of the Middle East. Bahrain has been independent from Persia since the 18th century, although it was a British protectorate until 1971." },
  { name: "Bangladeshi", adjective: "Bangladeshi", graphic_str: "bangladesh", legend: "The People's Republic of Bangladesh was formed from the former Pakistani territory of East Bengal following a war of independence." },
  { name: "Barbadian", adjective: "Barbadian", graphic_str: "barbados", legend: "Barbados is an island country in the Atlantic Ocean, about 100 km east of the Windward Islands in the Caribbean. Originally inhabited by Arawaks, the island was discovered by the Portuguese around 1500." },
  { name: "Barbarian", adjective: "Barbarian", graphic_str: "barbarian", legend: "Since the dawn of civilization, barbarians have been a threat to cultured peoples everywhere." },
  { name: "Barbarian", adjective: "Barbarian", graphic_str: "pirate", legend: "Since the dawn of civilization, barbarians have been a threat to cultured peoples everywhere." },
  { name: "Bashkir", adjective: "Bashkir", graphic_str: "bashkortostan", legend: "The Bashkirs are a Turkic-speaking nation in the southern Urals. Since the end of the 16th century, the Bashkirs were vassals of the Russian tsar, but have since participated in several uprisings against the Russian government." },
  { name: "Basque", adjective: "Basque", graphic_str: "euskadi", legend: "The Basques have lived since ancient times by the western foothills of the Pyrenees. The Kingdom of Navarre was the last independent Basque state, which fell to Aragon in the 16th century." },
  { name: "Bavarian", adjective: "Bavarian", graphic_str: "bavarian", legend: "Bavaria, before national unification in 1870 CE, was one of the largest of the German kingdoms." },
  { name: "Belarusian", adjective: "Belarusian", graphic_str: "belarus", legend: "Belarus was part of the ancient Slavic state of Kievan Rus', then subsequently Lithuania, Rzeczpospolita, the Russian Empire and the Soviet Union. Belarus became independent in 1991 with the dissolution of the Soviet Union." },
  { name: "Belgian", adjective: "Belgian", graphic_str: "belgium", legend: "Belgium gained independence from the Dutch Kingdom in 1830. Belgium is mainly characterized by its movement from a unified state to a federal one." },
  { name: "Belgic", adjective: "Belgic", graphic_str: "belgic", legend: "The Belgae were an Ancient Celtic tribe that inhabited the area that would later become the Roman province of Gallia Belgica. Their origin was perhaps mixed Celtic and Germanic, because they had come to Gaul from behind the Rhine and included some Germanic elements, but the names of their chiefs were Gallic." },
  { name: "Belizean", adjective: "Belizean", graphic_str: "belize", legend: "Belize is the smallest country of Central America. Once part of the Maya region, it was settled by British pirates and loggers in the 17th century." },
  { name: "Bengali", adjective: "Bengali", graphic_str: "bengal", legend: "Bengal is a region in the easternmost part of the Indian subcontinent. The first recorded independent king of the Bengali is Shashanka who reigned around 606 CE." },
  { name: "Benin", adjective: "Benin", graphic_str: "benin_ancient", legend: "Not to be confused with the modern republic of Benin, the Kingdom of Benin was founded by Edo speakers sometime between the 12th and 14th centuries. Benin united a large area of land west of the Niger river delta, reaching its peak in the 16th century." },
  { name: "Beninese", adjective: "Beninese", graphic_str: "benin", legend: "Once the site of the Dahomey kingdom, the country was colonized by France in the 19th century. Dahomey became independent in 1960." },
  { name: "Bhutanese", adjective: "Bhutanese", graphic_str: "bhutan", legend: "Located in the Himalayas, Bhutan is one of the most isolated countries in the world. Bhutan has not been conquered or occupied by foreign invaders for a millennium if not more." },
  { name: "Biafran", adjective: "Biafran", graphic_str: "biafra", legend: "Biafra declared independence from Nigeria in 1967 after years of ethnic, religious and economic tensions in newly independent Nigeria. A war between Nigeria and Biafra followed, which claimed up to two million lives, mostly because of famine and disease caused by the blockade of Biafran ports." },
  { name: "Bissau-Guinean", adjective: "Bissau-Guinean", graphic_str: "guinea-bissau", legend: "Guinea-Bissau is a country in West Africa. Formerly known as Portuguese Guinea, it declared independence in 1973." },
  { name: "Boer", adjective: "Boer", graphic_str: "boer", legend: "The Boers were descendants of Dutch colonists who settled in South Africa after 1650 CE. After migrating into the hinterland after the British takeover of South Africa, they briefly controlled a number of republics, including the Transvaal and the Orange Free State, before being defeated by the British in the war of 1899-1902." },
  { name: "Boian", adjective: "Boian", graphic_str: "boii", legend: "The Boii were an ancient Celtic tribe or tribal confederation inhabiting Central Europe and Northern Italy. The names of both Bohemia and Bavaria probably derive from this people." },
  { name: "Bolivian", adjective: "Bolivian", graphic_str: "bolivia", legend: "Bolivia is a landlocked country in South America with a large indigenous heritage. The country is named after Simón Bolivar." },
  { name: "Bosnian-Herzegovinian", adjective: "Bosnian-Herzegovinian", graphic_str: "bosnia", legend: "Bosnia and Herzegovina is a country in south-east Europe, and the home of three constituent peoples: Bosniaks, Serbs, and Croats." },
  { name: "Bosporan", adjective: "Bosporan", graphic_str: "bosporus", legend: "The Bosporan Kingdom was an ancient state in eastern Crimea and the Taman Peninsula on the shores of the Cimmerian Bosporus." },
  { name: "Botswanan", adjective: "Botswanan", graphic_str: "botswana", legend: "The Republic of Botswana is a country in Southern Africa. It gained independence from the UK in 1966." },
  { name: "Brandenburgian", adjective: "Brandenburgian", graphic_str: "brandenburg", legend: "Formerly the Northern March of East Francia, Brandenburg became an electorate of the Holy Roman Empire in the 12th century. The rulers of Brandenburg acquired Prussia in 1618 and was absorbed by Prussia in 1701." },
  { name: "Brazilian", adjective: "Brazilian", graphic_str: "brasil", legend: "Brazil was founded as a colony of Portugal but became independent in 1822 as a result of Portugal's occupation by Napoleonic France. The country was first established as an empire under the exiled Portuguese royal family." },
  { name: "Brazzaville-Congolese", adjective: "Brazzaville-Congolese", graphic_str: "r_congo", legend: "The Republic of the Congo is a country in Central Africa, not to be confused with the Democratic Republic of the Congo. Congo has been independent from France since 1960." },
  { name: "Breton", adjective: "Breton", graphic_str: "brittany", legend: "Known to the Romans as Armorica, Brittany had been Celtic speaking for many centuries before Britons arrived in the peninsula as mercenaries, colonists and refugees in response to the chaos in Gaul and the invasion of Britain by Germanic tribes in the fifth century CE. Over the centuries, use of the Breton language has been pushed towards the west of the peninsula, with people speaking French instead." },
  { name: "British", adjective: "British", graphic_str: "united_kingdom", legend: "The United Kingdom was created in 1707 as a negotiated agreement between the kingdom of England and the kingdom of Scotland. The country - also known as Great Britain - became the leading industrial and maritime power in the 19th century." },
  { name: "Briton", adjective: "Briton", graphic_str: "britannia", legend: "The Britons were the inhabitants of most of Great Britain during the Iron Age. They spoke Brythonic Celtic languages and are the ancestors of the modern Welsh, Cornish and Breton people." },
  { name: "Bruneian", adjective: "Bruneian", graphic_str: "brunei", legend: "Brunei Darussalam is a country on Borneo in the Malay achipelago. The sultanate dates from the 14th century and became a fairly powerful state a century later thanks to its control of the maritime trade in much of Southeast Asia." },
  { name: "Bulgarian", adjective: "Bulgarian", graphic_str: "bulgaria", legend: "Bulgar leader Khan Asparukh led his people into the northern Balkans, and founded Bulgaria in 681. This was the first Slavic nation-state in history." },
  { name: "Burgundian", adjective: "Burgundian", graphic_str: "burgundy", legend: "After the fall of the Western Roman Empire, a Germanic people known as the Burgundians settled in the river valleys of eastern Gaul, lending their name to the region. Centuries later, the Duchy of Burgundy was a prosperous country with the court in Dijon outshining that of Paris." },
  { name: "Burgundic", adjective: "Burgundic", graphic_str: "burgundic", legend: "The Burgundians were an ancient East Germanic people who probably originated on Bornholm island. After leaving Bornholm they lived between the Oder and Vistula rivers." },
  { name: "Burkinabé", adjective: "Burkinabé", graphic_str: "burkina_faso", legend: "Formerly Upper Volta, Burkina Faso is a country in inland West Africa. It achieved its independence from France in 1960." },
  { name: "Burmese", adjective: "Burmese", graphic_str: "myanmar", legend: "The Union of Burma (officially \"Myanmar" },
  { name: "Burundian", adjective: "Burundian", graphic_str: "burundi", legend: "A monarchy emerged in the Great Lakes region of East Africa in the 1100s, ruled by a Mwami (king) and several Ganwa (princes). It went through a period of expansion until the 1600s when it encompassed approximately the area of modern-day Burundi." },
  { name: "Buryat", adjective: "Buryat", graphic_str: "buryatia", legend: "According to Mongolian historical annals, the Buryats were forest dwelling Mongolian tribes living around Lake Baikal. In 1207 they were subjugated by Jochi, the eldest son of Genghis Khan." },
  { name: "Byzantine", adjective: "Byzantine", graphic_str: "byzantium", legend: "At the time of the decline of the old Roman empire, the Emperor Constantine moved the empire's capital to Byzantium and formed a new empire mostly known as the Eastern Roman empire or the Byzantine empire. This empire lasted until 1453 when its capital fell to the Ottomans." },
  { name: "Californian", adjective: "Californian", graphic_str: "california", legend: "California is the largest US state by population and economy. First populated by Native Americans, it was colonized by Spanish missionaries in the 18th century." },
  { name: "Cambodian", adjective: "Cambodian", graphic_str: "kampuchea", legend: "Kampuchea (known in English as Cambodia) is the modern successor state of the mighty Khmer Empire, which ruled most of the Indochinese Peninsula between the 11th and 14th centuries." },
  { name: "Cameroonian", adjective: "Cameroonian", graphic_str: "cameroon", legend: "Cameroon is a country in West Central Africa. Colonized by the Germans, it was divided between Britain and France after World War I." },
  { name: "Canadian", adjective: "Canadian", graphic_str: "canada", legend: "Geographically, Canada is the second largest country in world. The magnetic north pole currently lies on Canadian territory." },
  { name: "Cañari", adjective: "Cañari", graphic_str: "canar", legend: "The Cañaris were a pre-Columbian civilization in what is now Ecuador, whose existence can be traced from the 6th century onwards. They were one of the few Andean cultures not to worship the sun." },
  { name: "Cantonese", adjective: "Cantonese", graphic_str: "cantonese", legend: "The Cantonese are a sub-group of the Chinese people originating from Guangdong Province in Southern China comprising about 70 million people. The Cantonese are renowned for their music and food and constitute an important element in Overseas Chinese communities worldwide." },
  { name: "Cape Verdean", adjective: "CapeVerdean", graphic_str: "cape_verde", legend: "Cape Verde is an archipelago off the coast of West Africa. Before the islands were settled by the Portuguese in the 15th century they were probably uninhabited." },
  { name: "Carantanian", adjective: "Carantanian", graphic_str: "carantanian", legend: "The Carantanians or Alpine Slavs were an Early Medieval confederation of South West Slavic tribes who settled in modern-day Austria. The Duchy of Carantania was one of the earliest Slav states, existing since the seventh century CE." },
  { name: "Carthaginian", adjective: "Carthaginian", graphic_str: "cartago", legend: "The Carthaginians, descendants of Phoenician traders, ran a naval empire in the Mediterranean from the 5th to 2nd centuries BCE. Carthage was destroyed by Rome in 146 BCE." },
  { name: "Castilian", adjective: "Castilian", graphic_str: "castile", legend: "Castile emerged to become the most powerful of the medieval Spanish kingdoms. It absorbed Leon and later formed a personal union with Aragon." },
  { name: "Catalan", adjective: "Catalan", graphic_str: "catalan", legend: "During the Middle Ages, Catalan kings conquered and presided over several kingdoms on the shores of the Mediterranean Sea, from the Iberian peninsula to parts of Italy and Greece. This confederation/empire became a major naval and trading power in the Mediterranean area." },
  { name: "Celtiberian", adjective: "Celtiberian", graphic_str: "celtiberian", legend: "The Celtiberians were a people from East-Central Spain that lived during the last millennium BCE. They were of mixed Celtic and Iberian descent and were defeated by Rome in the Numantian War." },
  { name: "Celtic", adjective: "Celtic", graphic_str: "celtic", legend: "The Celts were an Indo-European ethno-linguistic complex in Western Europe, probably originating from the area between the upper Rhine and upper Danube, from the Urnfield culture and the western group of the Hallstatt culture. The Celts were known as cruel and savage warriors who terrorized the ancient civilized peoples of Europe and Asia Minor." },
  { name: "Central African", adjective: "CentralAfrican", graphic_str: "car", legend: "The Central African Republic is a country in Central Africa, formerly known as the French African territory of Ubangi-Shari. It was ruled briefly as a dictatorship in the 70s under Emperor Bokassa I during which it was called the Central African Empire." },
  { name: "Central American", adjective: "CentralAmerican", graphic_str: "central_america", legend: "During the colonial era Central America formed the Captaincy General of Guatemala. Central America declared independence from Spain in 1821, shortly joined Mexico, and then formed a federal republic." },
  { name: "Central Lithuanian", adjective: "CentralLithuanian", graphic_str: "central_lithuania", legend: "Lithuanian Poles are an ethnic minority in Lithuania, mainly in the Aukshtota region. They are a remnant of the Polish-Lithuanian Commonwealth - the Commonwealth of Two Nations, which was founded with the Union of Lublin in 1569." },
  { name: "Chadian", adjective: "Chadian", graphic_str: "chad", legend: "Chad is a landlocked country in Africa. Once the site of the Kanem-Bornu Empire, Chad was colonized by France in 1900." },
  { name: "Cham", adjective: "Cham", graphic_str: "cham", legend: "Champa was the name of a group of closely related polities in what is now the southern half of Vietnam. From the time of the earliest historical records, the Champa kings were Hindus who worshipped Shiva in particular." },
  { name: "Chananean", adjective: "Chananean", graphic_str: "chananea", legend: "Reports of chynocephaly (having the head of a dog or jackal) can be traced to Greek Antiquity. The physician Ctesias and the traveler Megasthenes placed them in India." },
  { name: "Chechen", adjective: "Chechen", graphic_str: "chechnya", legend: "Chechnya is an ancient nation in the Caucasus, currently part of the Russian Federation. In 1588, the Chechens voluntarily subjected themselves as vassals to the Moscovite tsar." },
  { name: "Cherokee", adjective: "Cherokee", graphic_str: "keetoowah", legend: "The Cherokee nation is the largest Native American nation in North America today." },
  { name: "Chiapanec", adjective: "Chiapanec", graphic_str: "chiapas", legend: "Chiapas is a state in southern Mexico. It was governed from Guatemala during the colonial era, but in 1824, after a brief independence, it chose to join Mexico." },
  { name: "Chickasaw", adjective: "Chickasaw", graphic_str: "chickasaw", legend: "One of the so-called Five Civilized Tribes, the Chickasaw occupied primarily what is today the northern part of the U. S." },
  { name: "Chilean", adjective: "Chilean", graphic_str: "chile", legend: "Chile is located on the south-western coast of South America. Chile declared its independence from Spain in 1810." },
  { name: "Chimu", adjective: "Chimu", graphic_str: "chimu", legend: "Inheritors of the Moche cultural tradition, Chimor began its expansion in the 12th century from the Moche river valley in what is now northern Peru. Their expansion continued until they were halted and conquered by the rising Inka Empire in 1470." },
  { name: "Chinese", adjective: "Chinese", graphic_str: "china", legend: "China is the oldest major civilization that is still in existence today, with written records dating back over 3,500 years. After first being unified by the Qin dynasty in 221 BCE, China alternated between periods of unity and disunity, and was occasionally conquered by external ethnicities." },
  { name: "Chinook", adjective: "Chinook", graphic_str: "clatsop", legend: "The Chinook Confederacy was a group of communities with common customs and language. They were a sedentary people living along the Columbia river in present-day Oregon and Washington in the United States." },
  { name: "Choctaw", adjective: "Choctaw", graphic_str: "choctaw", legend: "One of the so-called Five Civilized Tribes, the Choctaw traditionally occupied much of the middle and south of today's U. S." },
  { name: "Chola", adjective: "Chola", graphic_str: "chola", legend: "The Cholas were a Tamil dynasty centered in southern India that was unusually influential in northern India. They began as a tributary state to the Pallavas, but in the 9th century their power began to grow." },
  { name: "Chrobatian", adjective: "Chrobatian", graphic_str: "chrobatian", legend: "Chrobatia was an Early Medieval, semi-legendary Slavic state organized by the White Croats in a part of Central Europe that can not be conclusively identified today. The main source of the existence of a White Croatian state is a mention by the Byzantine Emperor Constantine VII Porphyrogennetos." },
  { name: "Chumash", adjective: "Chumash", graphic_str: "chumash", legend: "Inhabiting the Santa Barbara Channel Islands and the southern California coastline between Malibu and Paso Robles inland towards the San Joaquin valley, the Chumash lived in large permanent villages and maintained a semi-monetized economy. These villages came to be ruled by hereditary chiefs, who could be male or female." },
  { name: "Chuvash", adjective: "Chuvash", graphic_str: "chuvashia", legend: "Chuvashes are a Turkic ethnic group in Eastern European Russia and Western Siberia. They may be descendants of Old Bulgarian Turkic tribes and possibly Huns." },
  { name: "Circassian", adjective: "Circassian", graphic_str: "adygea", legend: "The Circassians are the indigenous peoples of the Northwest Caucasus. The Circassian or Adyghe language is part of the Northwest Caucasian language family, related to Kabardian, Abkhaz and Ubykh." },
  { name: "Colombian", adjective: "Colombian", graphic_str: "colombia", legend: "Colombia is a country in northern South America. The region was an Amerindian cultural center in pre-European time." },
  { name: "Comanche", adjective: "Comanche", graphic_str: "comanche", legend: "The Comanche or Numunu are a Native American ethnic group whose historic range (the Comancheria) consisted of present-day eastern New Mexico, southern Colorado, northeastern Arizona, southern Kansas, all of Oklahoma, and most of northwest Texas." },
  { name: "Comorian", adjective: "Comorian", graphic_str: "comoros", legend: "The Comoros is an island country in the Mozambique channel, consisting of Grande Comore, Moheli and Anjouan, although the Comoran government also claims Mayotte, which is currently a French overseas departement. Having been under Arab influence since the 8th century, the Comoros is the southernmost Muslim-majority country in the world." },
  { name: "Confederate", adjective: "Confederate", graphic_str: "southern_cross", legend: "The Confederate States of America was a splinter nation of the United States, formed by eleven Southern states, existing from 1861 to 1865. The states seceded from the United States because of political and cultural differences with the North, most prominently the issue of slavery, which they feared the government of the recently elected United States president Abraham Lincoln would abolish." },
  { name: "Congolese", adjective: "Congolese", graphic_str: "dr_congo", legend: "The Democratic Republic of the Congo is a big country in Central Africa. Despite (or because of) its wealth of natural resources it has been in ruins for most of its modern history." },
  { name: "Cornish", adjective: "Cornish", graphic_str: "cornwall", legend: "Cornwall is a region in the extreme southwest of England, traditionally the home of the legendary King Arthur." },
  { name: "Corsican", adjective: "Corsican", graphic_str: "corsica", legend: "For most of its history, Corsica has been ruled by foreign powers. Greeks, Etruscans, Romans, Vandals, Visigoths, Byzantines, Saracens, Lombards, the Papal States and Genoese all held sway over Corsica at one time or another." },
  { name: "Cossack", adjective: "Cossack", graphic_str: "cossack", legend: "The Zaporozhian Cossacks lived in Zaporozhia, in Central Ukraine. They were a multi-ethnic community with Ruthenians being the dominant element, organized in a military manner." },
  { name: "Costa Rican", adjective: "CostaRican", graphic_str: "costa_rica", legend: "Costa Rica became an independent republic in 1840. It has been without an army since 1949 and is one of the most democratic and wealthy countries of Latin America." },
  { name: "Coutense", adjective: "Coutense", graphic_str: "couto_misto", legend: "Couto Misto was a microstate on the border between Portugal and Spain. It consisted of three villages ruled by a republic, where the heads of families voted for a 'juiz." },
  { name: "Cree", adjective: "Cree", graphic_str: "innu", legend: "The Cree are the largest native group in Canada with over 200,000 members who speak an Algonquian language and often call themselves \"Iiyiyuu \" or \"Iinuu, \" meaning \"people. \" They originally inhabited much of Quebec, Labrador, Alberta, Saskatchewan, Ontario and Manitoba." },
  { name: "Cretan", adjective: "Cretan", graphic_str: "crete", legend: "Crete is an island in the Mediterranean Sea, the largest of the Greek Archipelago. In the 3rd and 2nd millennia BCE Crete was the site of Europe's first advanced civilization, the Minoan culture." },
  { name: "Crimean Tatar", adjective: "CrimeanTatar", graphic_str: "crimean_tatar", legend: "Historical feudal state on the Crimean Peninsula, existing from the 15th to the 18th century. Crimean Tatars invaded Poland and Russia, which caused wars with Turkey." },
  { name: "Croatian", adjective: "Croatian", graphic_str: "croatia", legend: "Croatia is the region of the Southern Slavs that was held by the Austro-Hungarian Empire, rather than coming under Ottoman rule after the collapse of Byzantium. During most of the 20th century it was part of the Yugoslav Federation." },
  { name: "Crusader", adjective: "Crusader", graphic_str: "jerusalem", legend: "The Crusades were a series of wars in which European armies tried to re-establish Christian control over the Holy Land. The First Crusade was called by Pope Urban II in 1095." },
  { name: "Cuban", adjective: "Cuban", graphic_str: "cuba", legend: "Cuba came under Spanish control in the 16th century. In the following centuries, the island became one of the leading producers of tobacco, sugar and coffee in the world." },
  { name: "Curonian", adjective: "Curonian", graphic_str: "courland", legend: "The Duchy of Courland and Semigallia was created as the result of the secularization of the Teutonic Order State. The dukes of Courland were vassals of Poland until its collapse." },
  { name: "Cuyavian", adjective: "Cuyavian", graphic_str: "cuyavia", legend: "Cuyavia is a historical region in Northern-Central Poland, bordered to the East by Masovia, on the West by Greater Poland and on the North by Pomerania." },
  { name: "Cypriot", adjective: "Cypriot", graphic_str: "cyprus", legend: "Cyprus became an independent republic on 16th August 1960. It is a Eurasian island country located in the eastern Mediterranean, south of Turkey and west of Syria and Lebanon." },
  { name: "Cyrenaican", adjective: "Cyrenaican", graphic_str: "cyrenaica", legend: "Cyrenaica is a historical region in Eastern Libya. In Classical Antiquity the region was part of the Greek cultural realm." },
  { name: "Czech", adjective: "Czech", graphic_str: "czech", legend: "Today's Czech Republic was until 1993 part of Czechoslovakia, which had been until 1918 part of the Austro-Hungarian Empire." },
  { name: "Czechoslovakian", adjective: "Czechoslovakian", graphic_str: "czechoslovakia", legend: "Czechoslovakia was founded in 1918. It was long the only democracy in Eastern Europe until it was overrun by the Nazis in 1939 and the Soviet Union in 1948." },
  { name: "Dacian", adjective: "Dacian", graphic_str: "dacian", legend: "The Dacians were ancient tribes who lived on the left bank of the Lower Danube in Dacia in what is now Romania. They were probably related to the Thracians and other Paleo-Balkanic tribes." },
  { name: "Dahomean", adjective: "Dahomean", graphic_str: "dahomey", legend: "The southern third of modern Benin was once a historic kingdom known variously as Agbome (c. 1600 - c." },
  { name: "Danish", adjective: "Danish", graphic_str: "denmark", legend: "The founding of the Danish kingdom is generally assigned to the reign of Harald Blåtand, who unified what is now Denmark between 958 CE and 988 CE." },
  { name: "Darfuri", adjective: "Darfuri", graphic_str: "darfur", legend: "The Sultanate of Darfur was an eastern so-called Sahelian state that from its location in the region just south of the Sahara benefited and prospered from trans-Saharan trade. The region had previously been dominated by the Daju and Tunjur ethnic groups, the latter of which is traditionally thought to have introduced Islam to the region." },
  { name: "Djiboutian", adjective: "Djiboutian", graphic_str: "djibouti", legend: "Djibouti is one of the smallest countries of Africa, located on the Gulf of Aden. It has been independent from France since 1977." },
  { name: "Dominican", adjective: "Dominican", graphic_str: "dominica", legend: "The island of Dominica was first sighted by Europeans, including Christopher Columbus, in 1493. Legend has it that the island was named so since the day of its first sighting was a Sunday." },
  { name: "Dominicano", adjective: "Dominicano", graphic_str: "dominican_republic", legend: "The Dominican Republic is located on the eastern two thirds of the Caribbean island of Hispaniola. Its capital - Santo Domingo - became the first permanent European settlement in the Americas when it was founded by Bartholomew Columbus in 1498." },
  { name: "Dryad", adjective: "Dryad", graphic_str: "dryad", legend: "Dryads are creatures of Greek myth; they are a type of nymph associated with trees. Dryads were generally considered to be shy and long-lived." },
  { name: "Dutch", adjective: "Dutch", graphic_str: "netherlands", legend: "When the Holy Roman Emperor sentenced the entire population to death, the people of the Netherlands revolted and declared themselves independent, forming the Union of Utrecht in 1579. The Netherlands grew to be a dominant maritime and economic power in the 17th century." },
  { name: "East German", adjective: "EastGerman", graphic_str: "ddr", legend: "The German Democratic Republic was founded in the Soviet Occupation Zone of postwar Germany in 1949. It was part of the Soviet dominated eastern bloc during the Cold War." },
  { name: "East Timorese", adjective: "EastTimorese", graphic_str: "east_timor", legend: "A former Portuguese colony, East Timor declared independence in 1975 but was overrun by Indonesian forces shortly thereafter. East Timor became the first newly sovereign state of the 21st century when Indonesia relinquished control on May 20, 2002." },
  { name: "Ecuadorian", adjective: "Ecuadorian", graphic_str: "ecuador", legend: "Ecuador is a country in western South America. It is divided into three very distinct geographic regions: the coastal lowlands, the mountains of the Andes and the jungles of the Oriente." },
  { name: "Egyptian", adjective: "Egyptian", graphic_str: "egypt_ancient", legend: "Egypt was the second-oldest of the world's civilizations. Since ancient times it has been unusually urbanized, supporting a large population on silt deposited by the annual floodings of the Nile." },
  { name: "Egyptian Arab", adjective: "EgyptianArab", graphic_str: "egypt", legend: "Modern Egypt is the most populous Middle Eastern country as well as one of the most populous in Africa. It is located on the site of one of the world's most ancient civilizations." },
  { name: "Elamite", adjective: "Elamite", graphic_str: "elam", legend: "Elam was an ancient civilization located in the area of modern southwest Iran, which arose around 3100 BCE. The Elamite language, written in cuneiform, is of unknown origin." },
  { name: "Emirati", adjective: "Emirati", graphic_str: "uae", legend: "The history of the United Arab Emirates goes back to the 7th century. In the 19th century the Emirates became a dependency of the United Kingdom." },
  { name: "English", adjective: "English", graphic_str: "england", legend: "England was unified by Alfred the Great of Wessex in the late 9th century, only to be conquered by William of Normandy a century later, in the last successful invasion of the country." },
  { name: "Epirote", adjective: "Epirote", graphic_str: "epirus", legend: "The Epirotes were the ancient inhabitants of the Epirus region in northwestern Greece. Their most powerful ruler Pyrrhus launched a campaign against Rome in Italy, which ended in the famous \"Pyrrhic Victory \"." },
  { name: "Equatoguinean", adjective: "Equatoguinean", graphic_str: "equatorial_guinea", legend: "Equatorial Guinea is a country in Africa. It is divided into a mainland part (Rio Muni) and the islands of Bioko and Annobon." },
  { name: "Eritrean", adjective: "Eritrean", graphic_str: "eritrea", legend: "Eritrea is a country in eastern Africa which borders Sudan, Ethiopia, and Djibouti. It was once the Kingdom of D'mt and was later conquered by Italy." },
  { name: "Esperant", adjective: "Esperant", graphic_str: "esperanto", legend: "The Esperants are a world community united by the Esperanto language." },
  { name: "Estonian", adjective: "Estonian", graphic_str: "estonia", legend: "Estonia is a small country on the south shore of the eastern Baltic Sea. Its people and language are closely related to those of Finland." },
  { name: "Ethiopian", adjective: "Ethiopian", graphic_str: "ethiopia", legend: "Ethiopia is the oldest nation in Africa and the only one to remain independent during European colonialism." },
  { name: "Etruscan", adjective: "Etruscan", graphic_str: "etruscan", legend: "The Etruscans were an ancient civilization in Etruria, Italy, known for their artistic achievements and building of necropolises. Their language is only partly deciphered and their origins are still debated." },
  { name: "European", adjective: "European", graphic_str: "europe", legend: "The foundation for the European Union was laid in 1957 with the Treaty of Rome. The EU project has developed since then and is beginning to resemble a fledgeling super state." },
  { name: "Evenki", adjective: "Evenki", graphic_str: "evenkia", legend: "The Evenks are a Tungusic ethnic group in Siberia, Mongolia, and northern China. Historical evidence suggests that they have lived in the Baikal area on today's Russian-Mongolian border since the Stone Age." },
  { name: "Faroese", adjective: "Faroese", graphic_str: "faroes", legend: "The Faroe Islands are an archipelago in the Northern Atlantic ocean. According to the sagas, they were first settled by Norsemen who fled the tyranny of Norway's king Harald Fairhair." },
  { name: "Fijian", adjective: "Fijian", graphic_str: "fiji", legend: "Fiji is the most populous of the small Oceanian island states. It consists of Viti Levu, Vanua Levu and hundreds of smaller islands." },
  { name: "Filipino", adjective: "Filipino", graphic_str: "philippines", legend: "After centuries of Spanish rule, the Philippines were ceded to the Americans in 1898. They attained home rule in 1935 and independence in 1946." },
  { name: "Finnish", adjective: "Finnish", graphic_str: "finland", legend: "Finland is a small, cold country on the northern fringe of Europe, noted for exporting timber, cellular phones, and world-class operating systems." },
  { name: "Flemish", adjective: "Flemish", graphic_str: "flanders", legend: "In the Middle Ages, Flanders was a county on the border of France and the Holy Roman Empire. In the 15th century, it came under Habsburg domination and subsequently it became one of the Seventeen Netherlands." },
  { name: "Florentine", adjective: "Florentine", graphic_str: "florence", legend: "The Florentine Republic was founded upon the overthrow of the Margraviate of Tuscany in 1115. Despite its seemingly endemic political intrigues, it became the most magnificent city-state of its era." },
  { name: "Floridian", adjective: "Floridian", graphic_str: "florida", legend: "Florida is the third most populous state of the USA and is well known for its tourism. It was repeatedly colonized by Spain and Great Britain before the \"Florida Patriots \" proclaimed the Republic of East Florida in 1812." },
  { name: "Formosan", adjective: "Formosan", graphic_str: "formosan", legend: "Taiwan is home to fourteen officially recognized and twelve unrecognized tribes, all of whom are traditionally speakers of a group of Austronesian languages known as Formosan. Historical linguists consider the island to be the home of the Austronesian family, as it is host to the most diverse set of Austronesian languages." },
  { name: "Franconian", adjective: "Franconian", graphic_str: "franconia", legend: "Franconia was one of the stem duchies of the Holy Roman Empire. Founded in the 9th century, unlike the other stem duchies it didn't manage to consolidate itself and by the 12th century it had completely disappeared." },
  { name: "Frankish", adjective: "Frankish", graphic_str: "france_old", legend: "The Franks were a Germanic confederation that formed in what is now Northwest Germany in the 3rd century CE. In the late 5th century their leader Clovis converted to Christianity, united the Frankish tribes and conquered much of Gaul." },
  { name: "French", adjective: "French", graphic_str: "france", legend: "France has long been a major power in Europe. French conquerors like Emperor Napoleon and King Charlemagne united large parts of Europe under the French flag." },
  { name: "Frisian", adjective: "Frisian", graphic_str: "frisia", legend: "Romans already mentioned the Frisii but historians are unsure whether they were the ancestors of today's Frisians or not. In the early Middle Ages the Frisians controlled a kingdom stretching from the Scheldt to Jutland." },
  { name: "Friulian", adjective: "Friulian", graphic_str: "friuli", legend: "Friuli is a region in north-eastern Italy. A duchy of the Lombards and then a march of the Franks, it was ruled by the Patriarchs of Aquileia from the 11th century onward." },
  { name: "Fulani", adjective: "Fulani", graphic_str: "sokoto", legend: "The Fulani or Fulbe are an ethnic group in West Africa. Originally pastoralists, in the 18th and 19th centuries they led the Fulani Jihads, founding a number of states across the region." },
  { name: "Gabonese", adjective: "Gabonese", graphic_str: "gabon", legend: "Gabon is a country on the Atlantic coast of Central Africa. Gabon, then inhabited by Bantu peoples, became a French protectorate in the 19th century." },
  { name: "Gaelic", adjective: "Gaelic", graphic_str: "gael", legend: "The Gaels were Celtic people, they may have originated in Spain but were first reported in Ireland. During the Migration Period the Gaels also moved to Scotland." },
  { name: "Galician", adjective: "Galician", graphic_str: "galicia", legend: "Galicia is a region in the northwest of Spain, just above Portugal." },
  { name: "Gallic", adjective: "Gallic", graphic_str: "gaul", legend: "The Gauls were a Celtic people occupying what is now France and Belgium. They lived in chiefdom-level societies that grew increasingly centralized and stratified under the influence of the Greek and Roman merchants and soldiers who came to Gaul." },
  { name: "Gambian", adjective: "Gambian", graphic_str: "gambia", legend: "The Gambia is a small country in West Africa, straddling both banks of the Gambia river. It achieved independence from the United Kingdom in 1965." },
  { name: "Genoese", adjective: "Genoese", graphic_str: "liguria", legend: "The Most Serene Republic of Genoa (Italian: Repubblica di Genova) was an independent state in Liguria on the northwestern Italian coast from the 11th century to 1797, when it was invaded by armies of Revolutionary France under Napoleon. It was then succeeded by the Ligurian Republic, which existed until 1805 before being annexed by the French Empire." },
  { name: "Georgian", adjective: "Georgian", graphic_str: "georgia", legend: "The Georgians were one of the first peoples in history to adopt Christianity, in the 300s CE." },
  { name: "Gepid", adjective: "Gepid", graphic_str: "gepid", legend: "The Gepids were a group of ancient East Germanic tribes, closely related to the Goths. Their original settlement was located on the Scandinavian Peninsula." },
  { name: "German", adjective: "German", graphic_str: "germany", legend: "Germany was united in 1871 by the Prussian military force. After World War I it became a republic, but fell into Nazism in 1933 and started World War II." },
  { name: "German Belgian", adjective: "GermanBelgian", graphic_str: "dgb", legend: "The German-speaking Community is one of the three federal communities of Belgium, part of the Walloon Region in the extreme east of the country. The area was annexed by Belgium after the First World War to compensate the country for the German occupation during that war." },
  { name: "Germanic", adjective: "Germanic", graphic_str: "germanic", legend: "The Germanic peoples are an ethno-linguistic complex in Northern and Northwestern Europe. The Germanic languages descended from a hypothetical Proto-Germanic language within the Indo-European language family." },
  { name: "Ghana", adjective: "Ghana", graphic_str: "ghana_ancient", legend: "The Ghana or Wagadou Empire existed in West Africa from the 9th to the 13th centuries CE. It takes its name from the king, whose title 'ghana ' means 'great warrior '." },
  { name: "Ghanaian", adjective: "Ghanaian", graphic_str: "ghana", legend: "Ghana takes its name from the old Ghana Empire. Known as the Gold Coast by the Europeans, the Portuguese, Dutch and Swedes founded outposts but in the 19th century Ghana became a British colony." },
  { name: "Ghaznavid", adjective: "Ghaznavid", graphic_str: "ghaznavid", legend: "The Ghaznavids were a Sunni Muslim dynasty of Turkish origin, reigning from 977 to 1186 CE in Afghanistan and Northern India, and at the peak of their power also in eastern Iran and Central Asia." },
  { name: "Göktürk", adjective: "Göktürk", graphic_str: "gokturk", legend: "The Göktürk or Old Turkic Khaganate was ruled by the Ashina dynasty which derived its legendary origins from the red she-wolf. The Göktürks were ancestors of the modern Turkic nations in Asia and Eastern Europe." },
  { name: "Golden Horde", adjective: "GoldenHorde", graphic_str: "golden_horde", legend: "The Golden Horde was a historical Mongol and Tatar state, founded around 1240 in the western part of the empire of Genghis Khan by his grandson Batu Khan, with its capital at Sarai Batu. After the conquests its greatest extent covered the territories from the Irtysh to the mountains of the Caucasus, Black Sea and the Volga and Kama basins." },
  { name: "Gothic", adjective: "Gothic", graphic_str: "gothic", legend: "The Goths were an East Germanic people who originated in what is now Poland or possibly in Scandinavia. They dominated Southeastern Europe in the fourth century CE." },
  { name: "Greater Polish", adjective: "GreaterPolish", graphic_str: "greater_poland", legend: "Greater Poland or Wielkopolska is a historic and geographic region of central-western Poland." },
  { name: "Greek", adjective: "Greek", graphic_str: "greece_ancient", legend: "The ancient Greeks, between Mycenae and the Roman conquest." },
  { name: "Greenlander", adjective: "Greenlander", graphic_str: "greenland", legend: "Legend says that the Great Shaman Qitdlarssuaq led the Inuit people to Thule (Qaanaaq) on the west coast of Greenland in the 10th century. Around the same time, Scandinavian settlers arrived at the fjords on the southwestern tip of the island." },
  { name: "Grenadian", adjective: "Grenadian", graphic_str: "grenada", legend: "Grenada is an island nation in the Caribbean. It gained independence from the United Kingdom in 1974." },
  { name: "Guanche", adjective: "Guanche", graphic_str: "guanche", legend: "The Guanches were the original inhabitants of the Canary Islands. Little is known of their origins, but it appears that they were related to the Berbers." },
  { name: "Guarani", adjective: "Guarani", graphic_str: "guarani", legend: "Numbering perhaps as many as 400,000 people at the time of European contact, the Aba (more popularly known as Guarani) lived primarily in what is now Paraguay in agricultural villages. Today their Guarani language is spoken by over 4 million people and is an official language of the nation of Paraguay." },
  { name: "Guatemalan", adjective: "Guatemalan", graphic_str: "guatemala", legend: "The ancient heartland of the Mayas, Guatemala was conquered by the Spanish in the 16th century. It became independent in 1821 but was part of the United States of Central America until 1840." },
  { name: "Guinean", adjective: "Guinean", graphic_str: "guinea", legend: "Guinea declared independence from France in 1958. Its first president Ahmed Sékou Touré continued to rule the country until his death in 1984." },
  { name: "Gupta", adjective: "Gupta", graphic_str: "gupta", legend: "The Gupta Empire was one of the great classical empires. It ruled northern India from around 240 to 550 CE." },
  { name: "Guyanese", adjective: "Guyanese", graphic_str: "guyana", legend: "Originally inhabited by the Arawk, Guyana was colonized by the Dutch but became a British colony after the Napoleonic Wars. It gained independence in 1966." },
  { name: "Haitian", adjective: "Haitian", graphic_str: "haiti", legend: "A slave rebellion led Haiti to independence in 1804. It was the first independent black republic and the second independent country in the Americas." },
  { name: "Han", adjective: "Han", graphic_str: "han", legend: "The Han people are the majority ethnic group in China, tracing their lineage back to \"Yandi \" (the Yan Emperor) and \"Huangdi \" (the Yellow Emperor), legendary god-kings of prehistory." },
  { name: "Hanoverian", adjective: "Hanoverian", graphic_str: "hanover", legend: "Hanover was a state in Northern Germany, in current Lower Saxony. From 1714 to 1837 Hanover and the United Kingdom were united in a personal union." },
  { name: "Hanseatic", adjective: "Hanseatic", graphic_str: "hansa", legend: "The Hanseatic League was a powerful alliance of trading cities which existed from the 12th to the 19th century. Hanseatic cities were found in the North Sea and Baltic regions." },
  { name: "Hasinay", adjective: "Hasinay", graphic_str: "caddo", legend: "A Caddoan political league from East Texas, the Hasinay Confederacy consisted of a group of agricultural villages. Though they were involved in trade networks connecting them with people as far west as the Puebloan polities of the American Southwest, their cultural ties were more strongly in line with the other mound-building cultures of the Southeast." },
  { name: "Hawaiian", adjective: "Hawaiian", graphic_str: "hawaii", legend: "The Kingdom of Hawaii was established in 1810 by King Kamehameha the Great. Abolished in 1893, and subsequently annexed to the United States, the former kingdom became the 50th state of the United States on August 21, 1959." },
  { name: "Hellenic", adjective: "Hellenic", graphic_str: "greece", legend: "The Hellenic Republic - also known as Greece - was created when the Hellenic people gained independence from the Ottoman Empire in 1832." },
  { name: "Helvetian", adjective: "Helvetian", graphic_str: "helvetii", legend: "The Helvetians (Latin: Helvetii) were an Ancient Celtic people, inhabiting what is now Switzerland and adjacent parts of France and Germany. Helvetians sometimes helped in the internal conflicts of Rome, for example, on the side of Cicero." },
  { name: "Hephthalite", adjective: "Hephthalite", graphic_str: "hephthalite", legend: "The Hephthalites were a Central Asian nomadic confederation of the 5th and 6th centuries CE. Their precise origins and composition remain obscure." },
  { name: "Hessian", adjective: "Hessian", graphic_str: "hesse", legend: "Hesse became a landgraviate of the Holy Roman Empire in the 13th century. In the 16th century it splintered into a number of smaller territories." },
  { name: "Himyarite", adjective: "Himyarite", graphic_str: "himyar", legend: "The Himyar were originally a mountain tribe in what is now Yemen that conquered the other South Arabian kingdoms, including Sabaea in 115 BCE, which were rich from the incense trade. The Himyar were castle- builders, finding it necessary to erect citadels to protect against Bedouin raids." },
  { name: "Hittite", adjective: "Hittite", graphic_str: "hittite", legend: "The Hittite kingdom lasted from about 1680 BCE to about 1180 BCE. They were the first civilization to discover iron working." },
  { name: "Holy Roman", adjective: "HolyRoman", graphic_str: "hre", legend: "The Holy Roman Empire was considered the successor to the Roman Empire, but as Voltaire once quipped it was neither Holy, nor Roman nor even less an Empire. Nonetheless it proved to be extremely durable, and lost territory only very slowly." },
  { name: "Honduran", adjective: "Honduran", graphic_str: "honduras", legend: "Honduras has been an independent republic since the dissolution of the Central American Federation in 1840. The archetypical 'banana republic', periods of dictatorship and of more or less democratic rule have followed each other." },
  { name: "Hopi", adjective: "Hopi", graphic_str: "hopi", legend: "A matrilineal culture in North America, who claim descent from the Hisatsinom. The Hopi live today on the Hopi Reservation in northeastern Arizona." },
  { name: "Hungarian", adjective: "Hungarian", graphic_str: "hungary", legend: "Legend says that Hungary was founded by Arpad in the 9th century." },
  { name: "Hunnic", adjective: "Hunnic", graphic_str: "hunnic", legend: "The European Huns were an ancient tribal confederation who first appeared in the 4th century. The Huns inhabited the Eurasian steppes and were known as formidable horse archers." },
  { name: "Iberian", adjective: "Iberian", graphic_str: "iberian", legend: "The Iberians were non-Indo-European inhabitants of the ancient Iberian Peninsula. Very little is known about their history." },
  { name: "Icelandic", adjective: "Icelandic", graphic_str: "iceland", legend: "Iceland was long one of the largest uninhabited islands in the world, until it was settled by Norwegian Vikings in the late 9th century. The island was kept initially under the Norwegian and later the Danish crown until independence from Denmark in 1944." },
  { name: "Illyrian", adjective: "Illyrian", graphic_str: "illyria", legend: "Illyrians were Indo-European tribes who appeared in the western part of the Balkan Peninsula before 1000 BCE, including Corcyra island and Ambracia bay in prehistoric Epirus to the south. They mixed with Thracians in Dardania to the east, and settled Messapia across the Adriatic Sea." },
  { name: "Inca", adjective: "Inca", graphic_str: "inca", legend: "The Inca were an Amerind people of the Northern Andes who conquered an empire stretching along the west coast of South America from what is now southern Chile nearly to the Equator. They had the bad timing to do it just a few decades before the Spanish conquistadors arrived in their part of the world in the 1530s CE." },
  { name: "Indian", adjective: "Indian", graphic_str: "india", legend: "The Republic of India was created in 1950 following a non-violent independence movement led by Mahatma Gandhi. With more than a billion inhabitants it is the world's second most populous country as well as the world's largest democracy." },
  { name: "Indo-European", adjective: "Indo-European", graphic_str: "indoeuropean", legend: "The Indo-Europeans were a hypothetical ancient people who were linguistically ancestral to modern peoples in Europe and South and West Asia. They probably existed about 5000 years ago somewhere on the Eurasian steppes, but their true origins remain a mystery." },
  { name: "Indonesian", adjective: "Indonesian", graphic_str: "indonesia", legend: "Indonesia is a large country on the Malay Archipelago with central government on the island of Java. The country has a Muslim majority and is one of the most populous in the world." },
  { name: "Inuit", adjective: "Inuit", graphic_str: "nunavut", legend: "The Inuits are a group of peoples inhabiting the Arctic areas of North America and Siberia. The Canadian territory of Nunavut has a majority population of Inuits; the name of the territory means \"our land \" in Inuktitut." },
  { name: "Iranian", adjective: "Iranian", graphic_str: "iran", legend: "Iran means \"Land of the Aryans \" - long known as Persia in the Western world. The country is today an Islamic Republic and a major power in the Middle East." },
  { name: "Iraqi", adjective: "Iraqi", graphic_str: "iraq", legend: "Iraq was founded after the fall of the Ottoman empire. It is encompassing the ancient region of Mesopotamia at the confluence of the Tigris and Euphrates rivers." },
  { name: "Irish", adjective: "Irish", graphic_str: "ireland", legend: "Ireland held out against the Romans and Vikings but was conquered by the Normans in 1171. It was ruled by the English until 1922 when most of the country was granted limited autonomy, becoming a republic in 1949." },
  { name: "Iroquois", adjective: "Iroquois", graphic_str: "iroquois", legend: "The Iroquois Confederacy - known as Haudenosaunee in their own language - was a North American group of nations with common language and culture. They were based in what is now upstate New York and consisted originally of five nations: Seneca, Cayuga, Onondaga, Oneida and Mohawk." },
  { name: "Islamic State", adjective: "IslamicState", graphic_str: "islamic-state", legend: "The Islamic State, also known as ISIS or ISIL, emerged in 2014 during the Syrian civil war, declaring a self-proclaimed caliphate. Rooted in extremist interpretations of Sunni Islam, it aimed to establish a global theocratic state." },
  { name: "Israeli", adjective: "Israeli", graphic_str: "israel", legend: "The nation of Israel was founded in 1948 as a scattered collection of cantons in British Palestine, and has gradually expanded through winning wars in 1948, 1967 and 1973." },
  { name: "Israelite", adjective: "Israelite", graphic_str: "israel_ancient", legend: "Israel was a Jewish kingdom on the eastern shore of the Mediterranean founded around 1000 BCE. Much of its history is told in the holy books of the Abrahamic religions." },
  { name: "Italian", adjective: "Italian", graphic_str: "italy", legend: "The Italian nation was unified in 1870 CE after decades of campaigning by indigenous nationalists. It was a monarchy under the House of Savoy until 1922, then a fascist state until 1945 after which democracy was restored by the World War II victors." },
  { name: "Italian Greek", adjective: "ItalianGreek", graphic_str: "italian_greek", legend: "Ancient Magna Graecia was a complex of Greek cities-colonies on the coasts of Italy and Sicily, founded during the Greek Colonization. They played an important role in the development of Etruscan and Roman cultures." },
  { name: "Ivoirian", adjective: "Ivoirian", graphic_str: "ivory_coast", legend: "Ivory Coast or Côte d'Ivoire achieved independence in 1960. It has been relatively stable compared to other West African countries, but in the 2000s it lived through a civil war." },
  { name: "Jaffna", adjective: "Jaffna", graphic_str: "jaffna", legend: "The Jaffna Kingdom was a medieval Tamil kingdom based in the north of Sri Lanka. It was a successful southern rival to the Chola Empire on the Indian mainland." },
  { name: "Jamaican", adjective: "Jamaican", graphic_str: "jamaica", legend: "Columbus landed on Jamaica in 1494. The island was colonized by the Spanish but in 1655 it was conquered by the English, who turned the island into a slave-based plantation economy." },
  { name: "Japanese", adjective: "Japanese", graphic_str: "japan", legend: "According to traditional Japanese mythology, Japan was founded in the 7th century BCE by the ancestral Emperor Jimmu." },
  { name: "Jolof", adjective: "Jolof", graphic_str: "jolof", legend: "Also called Wolof, the Kingdom was formed between the Senegal and Gambia rivers in the 14th century. The King, or Burba Jolof, was beholden to a handful of powerful regional noblemen who acknowledged kinship with the king but developed personal power bases as well." },
  { name: "Jordanian", adjective: "Jordanian", graphic_str: "jordan", legend: "The Hashemite Kingdom of Jordan is a country in the Middle East. During Antiquity the country was the site of numerous ancient civilizations, including the Nabateans who built the city of Petra." },
  { name: "Kalmyk", adjective: "Kalmyk", graphic_str: "kalmykia", legend: "The Kalmyks are a Western Mongolian ethnic group living in Kalmykia in southern Russia. They migrated to the Caspian plains in the 17th century and formed a khanate that was allied with Russia." },
  { name: "Kanem-Bornu", adjective: "Kanem-Bornu", graphic_str: "kanem-bornu", legend: "This empire lasted in some form from the 9th-century until 1893 in modern Chad and Nigeria and controlled much of the trans-Saharan trade." },
  { name: "Karabakhi", adjective: "Karabakhi", graphic_str: "nagorno_karabakh", legend: "Although mainly inhabited by Armenians, Nagorno-Karabakh was awarded to the Azeri SSR after the Soviet Union overran the Caucasus in the 1920s. Shortly before the collapse of the Soviet Union, the region declared its independence from Azerbaijan, leading to a war between Nagorno-Karabakh and Armenia on one side against Azerbaijan on the other side." },
  { name: "Karelian", adjective: "Karelian", graphic_str: "karelia", legend: "The Karelians are a Finno-Ugric people inhabiting Karelia, a region currently divided between Finland and Russia. They are closely related to the Finns." },
  { name: "Karen", adjective: "Karen", graphic_str: "karen", legend: "Karens are a hardy mountain people who have lived on the western fringes of Burmese kingdoms throughout recorded history. Their own oral history suggests that they at some point migrated southwards through the Gobi Desert to reach their current homeland." },
  { name: "Kashmiri", adjective: "Kashmiri", graphic_str: "kashmir", legend: "The Kashmir valley is situated by the western foothills of the Himalayas. Having been inhabited for millennia, it is a melting pot of Hindu, Tibetan, and Islamic culture." },
  { name: "Kashubian", adjective: "Kashubian", graphic_str: "kashubia", legend: "Kashubia is a historical region of north-central Poland. The name of the land, whose etymology is still unknown, was first mentioned in the 13th century." },
  { name: "Katangan", adjective: "Katangan", graphic_str: "katanga", legend: "Katanga, the southernmost part of the Democratic Republic of the Congo, rich in minerals and once home to the Yeke Kingdom. The region seceded from Congo a few days after that country's independence from Belgium in 1960." },
  { name: "Kazakh", adjective: "Kazakh", graphic_str: "kazakhstan", legend: "Kazakhs are descendants of Turkic and Mongolian nomadic tribes. Conquered by Russia in the 18th century, Kazakhstan became independent in 1991 with the dissolution of the Soviet Union." },
  { name: "Kenyan", adjective: "Kenyan", graphic_str: "kenya", legend: "Kenya gained independence from Britain in December 1963." },
  { name: "Khazar", adjective: "Khazar", graphic_str: "khazaria", legend: "The Khazars founded a steppe empire on the plains of Southern Russia in the Early Middle Ages. Originally shamanists, they adopted Judaism as their state religion." },
  { name: "Khmer", adjective: "Khmer", graphic_str: "khmer", legend: "The Khmer Empire, established in 802 CE, dominated Southeast Asia for many centuries during the Middle Ages. Heavily influenced by Indian culture, the Khmers were great builders who erected innumerable stone temples to Hindu deities." },
  { name: "Khoisan", adjective: "Khoisan", graphic_str: "khoisan", legend: "Khoisan speakers are typically divided between the Khoikhoi, traditionally herders, and the San, traditionally hunter gatherers. They are traditionally among the most egalitarian societies on the planet." },
  { name: "Khwarezmian", adjective: "Khwarezmian", graphic_str: "khwarezm", legend: "Known by the Greeks as Chorasmia, Khwarezm was an urbanized, centralized, and militarized state south of the Aral sea in Central Asia, controlling portions of the Silk Road. It was loosely controlled as a satrapy under the Achaemenid and Sassanid Persian dynasties and was the mythic homeland of Zarathustra, the founder of Zoroastrianism." },
  { name: "Kievan Rus'", adjective: "KievanRus'", graphic_str: "kiev", legend: "The Kievan Rus' were a Medieval Slavic monarchy. It was centered in Kiev after that city was conquered by Oleg of Novgorod." },
  { name: "Kiribati", adjective: "Kiribati", graphic_str: "kiribati", legend: "The Gilbert Islands, known in Gilbertese as Tungaru, are an island chain in the Pacific Ocean. Inhabited by Micronesians since prehistoric times, they were united under a common chiefdom in the late 19th century." },
  { name: "Kittitian and Nevisian", adjective: "KittitianandNevisian", graphic_str: "saint_kitts_and_nevis", legend: "Saint Kitts and Nevis is a nation in the Caribbean located on the eponymous two islands. It is the smallest country in the Americas and the world's smallest federation." },
  { name: "Knights Templar", adjective: "KnightsTemplar", graphic_str: "templar", legend: "The Knights Templar were formed after the first Crusade in order to protect Pilgrims on their journeys in the Holy Land. The organization grew to immense power and wealth in the next 200 years, and were the innovators of many modern concepts such as Banking." },
  { name: "Komi", adjective: "Komi", graphic_str: "komi", legend: "The Komi are a Finno-Ugric people living in the northern part of European Russia. In the Middle Ages, the area inhabited by people of Komi was dominated by the Republic of Novgorod." },
  { name: "Kongo", adjective: "Kongo", graphic_str: "kongo", legend: "This Kingdom, lasting from roughly 1400 CE until the late 19th century, existed in the present-day countries of Angola and the Democratic Republic of the Congo. Soon after its formation, Portuguese explorers, missionaries and slavers began to arrive and exerted considerable influence in the Kingdom." },
  { name: "Korean", adjective: "Korean", graphic_str: "korea_ancient", legend: "According to legend, the first Korean kingdom was founded in prehistory by the ancestral Tangun in southern Manchuria. The Korean kingdoms were united in 668 by king Munmu." },
  { name: "Kosovar", adjective: "Kosovar", graphic_str: "kosovo", legend: "Kosovo is a country on the Balkans. It declared independence in 2008." },
  { name: "Kuna", adjective: "Kuna", graphic_str: "kuna_yala", legend: "The Kunas are a Chibchan people living on the Isthmus of Darien, where North and South America meet. In 1925 Kuna chief Nele Kantule led a revolt against the Panamanian authorities." },
  { name: "Kurdish", adjective: "Kurdish", graphic_str: "kurd", legend: "The Kurds are a distinct ethno-linguistic group speaking an Indo-Aryan language. Their traditional homeland Kurdistan is situated in the northern Middle East and partitioned between Iraq, Turkey, Syria, and Iran." },
  { name: "Kushan", adjective: "Kushan", graphic_str: "kushan", legend: "The Kushans were an ancient Indo-European people, perhaps of Tocharian origin, originally leading a nomadic life in Central Asia. Under pressure from Turkic peoples they left their old lands and migrated to India." },
  { name: "Kuwaiti", adjective: "Kuwaiti", graphic_str: "kuwait", legend: "Kuwait is an Arab country, bordered by Iraq, Saudi Arabia and the Persian Gulf. It was founded in 1756 by the Sabah dynasty, who has ruled the country ever since." },
  { name: "Kyrgyz", adjective: "Kyrgyz", graphic_str: "kyrgyzstan", legend: "Nation in Central Asia. Conquered by the Russian Empire in the 19th century, Kyrgyzstan got independence from the Soviet Union in 1991." },
  { name: "Langobardic", adjective: "Langobardic", graphic_str: "lombardy", legend: "The Langobards were an ancient Germanic people. They originated from Scandinavia but settled in the area on the lower Elbe." },
  { name: "Lankese", adjective: "Lankese", graphic_str: "srilanka", legend: "Prince Vijaya came to Sri Lanka from Orissa, in north-eastern India, during the 6th century BCE and founded the Sinhalese kingdom there. During British colonialism the country was known as Ceylon." },
  { name: "Laotian", adjective: "Laotian", graphic_str: "laos", legend: "The history of Laos starts with the Lan Xang kingdom created in the 14th century and ended in late 18th century with invasion of Siam (Thailand). In the end of the 19th century, Laos became part of French Indochina." },
  { name: "Latin", adjective: "Latin", graphic_str: "latin_empire", legend: "The Latin Empire was a Medieval state created by Crusaders after their capture of Constantinople during the Fourth Crusade in 1204, intended as a Roman Catholic-friendly replacement of the Byzantine Empire. In Greek history the period of rule by the Latin Empire and its successor splinter realms is known as the \"Frankokratia \", rule of the Franks." },
  { name: "Latvian", adjective: "Latvian", graphic_str: "latvia", legend: "In the aftermath of World War I Latvia proclaimed its independence from Russia. In 1940, Latvia was forcibly occupied by the Soviet Union." },
  { name: "Lebanese", adjective: "Lebanese", graphic_str: "lebanon", legend: "Located in the Levant, the Eastern shore of the Mediterranean, Lebanon houses some of the oldest traces of human civilization. The old homeland of the Phoenicians, Lebanon has since been ruled by many empires." },
  { name: "Lendian", adjective: "Lendian", graphic_str: "lendian", legend: "The Lendians were a confederation of West Slavic, Lechitic tribes inhabiting the borderland areas of today's Poland and Ukraine. Their land was the object of rivalry between Poland and the Kievan Rus' at the time of the early Piast dynasty." },
  { name: "Leonese", adjective: "Leonese", graphic_str: "leon", legend: "Leon was a medieval kingdom in the northwestern part of the Iberian peninsula. Currently Leon is part of the Spanish autonomous community of Castile and Leon." },
  { name: "Lesothoan", adjective: "Lesothoan", graphic_str: "lesotho", legend: "Lesotho first formed a unified polity in the early 19th century under king Moshoeshoe I, who united the Sotho clans. Moshoeshoe sought protection from the British against Boer incursions and in 1869 the country turned into the British protectorate of Basutoland." },
  { name: "Liberian", adjective: "Liberian", graphic_str: "liberia", legend: "Liberia is a country in West Africa, founded in the first half of the 19th century as a country for liberated African-American slaves. Liberia's history has been characterized by tensions between the dominant Americo-Liberian minority and the indigenous majority." },
  { name: "Liburnian", adjective: "Liburnian", graphic_str: "liburnian", legend: "The Liburnians were an ancient Indo-European tribe living along the Northeastern Adriatic coast in modern Croatia. They were probably distinct from their neighbors, the Illyrians, and spoke an Italic language." },
  { name: "Libyan", adjective: "Libyan", graphic_str: "libya", legend: "The region that is now Libya was a Roman colony until it was conquered by the Arab civilization in the 7th century. In 1912 it came under the control of Italy and after the Second World War Libya was granted independence as a condition of the Allied peace treaty with Italy." },
  { name: "Liechtensteiner", adjective: "Liechtensteiner", graphic_str: "liechtenstein", legend: "The Principality of Liechtenstein is a tiny, doubly landlocked alpine country in Western Europe, bordered by Switzerland to its west and by Austria to its east. The Principality was formed by the merger of Vaduz and Schellenberg in 1719." },
  { name: "Liegean", adjective: "Liegean", graphic_str: "luik", legend: "Liege was constituted in ecclesiastic principalty in 985, when Bishop Notger was granted the control of several cities in current Belgium. As a federated state of the Holy Roman Empire, it was characterized with large civil liberties for which liegean struggled strongly for." },
  { name: "Ligurian", adjective: "Ligurian", graphic_str: "ligurian", legend: "The Ligures were a pre-Roman tribal complex in what is now Northwestern Italy and Southern France. Their language is of uncertain origin, perhaps Para-Celtic or Pre-Indo-European." },
  { name: "Lipka Tatar", adjective: "LipkaTatar", graphic_str: "lipkatatar", legend: "The Lipka Tatars are descendants of Tatars who migrated to the Polish-Lithuanian Commonwealth from the Crimean Khanate and the Golden Horde. Their name comes from the Turkish name of Lithuania." },
  { name: "Lippian", adjective: "Lippian", graphic_str: "lippe", legend: "Lippe was a historical state in Germany. It was located between the Weser River and the southeast part of the Teutoburg forest." },
  { name: "Lithuanian", adjective: "Lithuanian", graphic_str: "lithuania", legend: "Lithuania is a small country on the south coast of the Baltic Sea, northeast of Poland. Lithuanian is the most archaic and complex of the northern Indo-European languages." },
  { name: "Lojbanistani", adjective: "Lojbanistani", graphic_str: "jbonai", legend: "Lojbanistan is a fictional place where people speak Lojban. Lojban is a constructed language meant for human communication." },
  { name: "Lorrain", adjective: "Lorrain", graphic_str: "lorraine", legend: "Lorraine or Lotharingia was formed as the middle kingdom when the Frankish empire was split in three in 843. Initially stretching from the North Sea to the Mediterranean, its territory was mutilated during the struggles between the various Frankish dynasties." },
  { name: "Luwian", adjective: "Luwian", graphic_str: "luwian", legend: "The Luwians were an ancient Indo-European Anatolian people who lived in the late Bronze Age. For a time after the fall of the Hittite Empire they took a dominant role in the region." },
  { name: "Luxembourgish", adjective: "Luxembourgish", graphic_str: "luxembourg", legend: "One of Europe's smaller countries, Luxembourg was founded as a county in 963. In 1815 it was elevated to a Grand Duchy in a personal union with the Netherlands, which was severed in 1890." },
  { name: "Lycian", adjective: "Lycian", graphic_str: "lycian", legend: "Lycia was an ancient Southwest Anatolian state which existed from the 15th to the 6th century BCE. Lycians were allies of Troy during the Trojan War, when they were led by the legendary heroes Sarpedon and Glaucus." },
  { name: "Maasai", adjective: "Maasai", graphic_str: "maasai", legend: "The Maasai are an indigenous African ethnic group of semi-nomadic people located in Kenya and northern Tanzania. Due to their distinctive customs and dress and residence near the many game parks of East Africa, they are among the most well known of African ethnic groups." },
  { name: "Macedon", adjective: "Macedon", graphic_str: "macedon", legend: "The Kingdom of Macedonia was located in the southern Balkans. Under Alexander the Great it became one of the most powerful states in the world but it splintered into several states after Alexander's death." },
  { name: "Macedonian", adjective: "Macedonian", graphic_str: "macedonia", legend: "The Republic of Macedonia is located in the south-central part of the Balkan peninsula. It declared independence from Yugoslavia in 1991." },
  { name: "Majapahit", adjective: "Majapahit", graphic_str: "majapahit", legend: "This empire began in 1293 CE when a local prince used invading Yuan dynasty troops to his own advantage by having them defeat his enemies and then expelling them. The Majapahit, centered in eastern Java, was heavily influenced by Buddhism and Hinduism and was a major regional power in the insular Southeast Asian world, a position which allowed them to control much of the trade between China, India and the Middle East." },
  { name: "Malagasy", adjective: "Malagasy", graphic_str: "madagascar", legend: "The Malagasy are the people of Madagascar. For centuries, tribes from Indonesia, East Africa and the Arab world have gathered on the island." },
  { name: "Malawian", adjective: "Malawian", graphic_str: "malawi", legend: "Called Nyasaland by the British, Malawi adopted its current name, referring to the old Maravi Empire upon independence in 1964. The country's politics were dominated by Dr." },
  { name: "Malaysian", adjective: "Malaysian", graphic_str: "malaysia", legend: "Malaysia was started with the founding of Malacca (Melaka) by Parameswara in the early 14th century." },
  { name: "Maldivian", adjective: "Maldivian", graphic_str: "maldives", legend: "The Maldives are an archipelago in the Indian Ocean and the smallest country of Asia. According to tradition, the Maldives became a united sultanate when the Cholas were expelled in the 12th century." },
  { name: "Mali", adjective: "Mali", graphic_str: "mali_ancient", legend: "Sub-Saharan Africa has been a cultural and ethnical melting pot for millennia. In medieval times, the region was home to a succession of empires called the Sahelian kingdoms." },
  { name: "Malian", adjective: "Malian", graphic_str: "mali", legend: "Mali is a large country in Western Africa. Once part of French Sudan, it gained independence together with Senegal in 1959." },
  { name: "Maltese", adjective: "Maltese", graphic_str: "malta", legend: "Malta was first settled around 5200 BCE. Over the centuries, the islands have been ruled by the Phoenicians, Romans, Fatimids, Sicilians, Knights Hospitaller, French, and British." },
  { name: "Mamluk", adjective: "Mamluk", graphic_str: "mamluk", legend: "The Mamluks were an Egyptian warrior caste who were recruited from slaves of Turkish or Caucasian origin. The Mamluks were known as elite military units." },
  { name: "Manchu", adjective: "Manchu", graphic_str: "manchuria", legend: "The Manchus were a semi-nomadic people originating from the region called Manchuria in Northeast Asia. In the 17th century they conquered and ruled China as the Manchu Empire until 1911." },
  { name: "Manx", adjective: "Manx", graphic_str: "man", legend: "The Isle of Man is an island in the British Isles located between Britain and Ireland. Formally not a part of United Kingdom, it is a self-governing British Crown Dependency." },
  { name: "Maori", adjective: "Maori", graphic_str: "maori", legend: "The Maori are a Polynesian people that migrated to and settled the island group that is now New Zealand. According to archeological evidence, the migration commenced in the 900s and continued until the 1400s." },
  { name: "Mapuche", adjective: "Mapuche", graphic_str: "mapuche", legend: "The Mapuche people successfully resisted the expansion of the Inka empire, halting them at the Maule river in what is now central Chile. They proved to be stubborn opponents of the Spanish, too, who, along with their Chilean successors, took 300 years to conquer them." },
  { name: "Marathi", adjective: "Marathi", graphic_str: "marathi", legend: "The Marathi are people who inhabit the state of Maharashtra in India. In the 17th century, the Marathi prince Shivaji established the Maratha confederacy, waging war on the Moghul empire and eventually replacing the Moghuls as the main power on the Indian subcontinent." },
  { name: "Marshallese", adjective: "Marshallese", graphic_str: "marshall_islands", legend: "The Marshall Islands is a country in the Western Pacific, just north of the Equator, consisting of a large number of islands and atolls. Populated primarily by Micronesians, the islands became an independent republic in free association with the United States in 1986." },
  { name: "Martian", adjective: "Martian", graphic_str: "mars", legend: "Marsmen landed on Earth in 4000 BCE!" },
  { name: "Mauritanian", adjective: "Mauritanian", graphic_str: "mauritania", legend: "Mauritania is a country in North West Africa, where the Arab and Sub-Saharan African worlds meet. Mauritania became Islamized from the 11th century onwards." },
  { name: "Mauritian", adjective: "Mauritian", graphic_str: "mauritius", legend: "Mauritius is an island in the Indian Ocean. It was first settled by the Dutch, who named it after Maurice of Nassau." },
  { name: "Mayan", adjective: "Mayan", graphic_str: "maya", legend: "The Mayans were a Mesoamerican civilization. They are famous for building great pyramids and palaces in the jungle." },
  { name: "Mazovian", adjective: "Mazovian", graphic_str: "mazovia", legend: "Mazovia is a historic and geographic region of central-eastern Poland." },
  { name: "Mecklenburgian", adjective: "Mecklenburgian", graphic_str: "mecklenburg", legend: "Mecklenburg was erected in the 12th century. Its ruling house, the Obrodites, were of Slavic origin - unique amongst the German states." },
  { name: "Median", adjective: "Median", graphic_str: "median", legend: "Media was an ancient Iranian state that was created by a Western Iranic people, the Medes, relatives of the European Scythians. Their state preceded the Persian Achaemenid Empire, which was formed as a result of a rebellion of the Persians against the Median ruler Astyages." },
  { name: "Messapian", adjective: "Messapian", graphic_str: "messapian", legend: "The Messapii were an Indo-European tribe that inhabited, in ancient times, Apulia, the south-eastern peninsula of Italy, before being absorbed by the Romans." },
  { name: "Métis", adjective: "Métis", graphic_str: "metis", legend: "The Métis are a people of mixed First Nations (Native American) and European (mostly French) descent living mainly in the Canadian prairie provinces. Together with the First Nations and the Inuit they form one of the three indigenous groups of Canada." },
  { name: "Mexican", adjective: "Mexican", graphic_str: "mexico", legend: "Mexico borrows its name from the Mexica people, another name for the Aztecs. It achieved independence from Spain in 1821." },
  { name: "Mi'kmaq", adjective: "Mi'kmaq", graphic_str: "mikmaq", legend: "Today numbering roughly 25,000, the Mi'kmaq inhabited (and largely continue to) Nova Scotia. The first Mi'kmaq to convert to Christianity did so in 1610 under French suzerainty." },
  { name: "Miao", adjective: "Miao", graphic_str: "hainan", legend: "According to Chinese legend, the Yellow Emperor of Huaxia battled and defeated Chi You, leader of the Nine Li tribe, at the Battle of Zhuolu in the 26th century BCE. For the Miao people of modern-day China, Chi You - whom they refer to as \"Txiv Yawg \" - is a mythical king and founding father of their nation." },
  { name: "Micronesian", adjective: "Micronesian", graphic_str: "micronesia", legend: "Micronesia is located in the Central Western Pacific. The site of several ancient seafaring cultures, nowadays most of the region is governed by the Federated States of Micronesia." },
  { name: "Milanese", adjective: "Milanese", graphic_str: "milan", legend: "Milan is the capital of Lombardy, a region in Northern Italy. From 1395 to 1797 it was the seat of the Duchy of Milan." },
  { name: "Miskito", adjective: "Miskito", graphic_str: "miskito", legend: "Living along the eponymous Miskito Coast of Nicaragua and Honduras, the Miskito now number around 200,000 people. In 1625, the Miskito came into a long-lasting political relationship with the British Empire, whose interests in the Caribbean were contrary to those of the Spanish Empire." },
  { name: "Mitanni", adjective: "Mitanni", graphic_str: "mitanni", legend: "Mitanni was an ancient Hurrian kingdom in what is now Northern Syria and Iraq. Mitanni was at the height of its power during the 14th century BCE, during which it rivalled Egypt." },
  { name: "Mixtec", adjective: "Mixtec", graphic_str: "mixtec", legend: "The Mixtecs or Ñuu Savi were one of the major Mesoamerican civilizations. The Mixtec territory was formed by a large number of city states." },
  { name: "Moldovan", adjective: "Moldovan", graphic_str: "moldova", legend: "Moldova was conquered by the Ottomans in the 16th century. Then in 1812 Moldova became part of the Russian Empire." },
  { name: "Moluccan", adjective: "Moluccan", graphic_str: "moluccas", legend: "The Moluccas, known as the Spice Islands during the era of colonizations, are an island group in the Indonesian archipelago. Inhabited by Malay peoples, the islands were contested by the Spanish, Portuguese and English but ended up under firm Dutch control by the 16th century." },
  { name: "Mon", adjective: "Mon", graphic_str: "mon", legend: "The Mon people were among the earliest inhabitants of Southeast Asia and instrumental in the spread of Buddhism in the region." },
  { name: "Monegasque", adjective: "Monegasque", graphic_str: "monaco_alternative", legend: "With only two square kilometers, Monaco is the second smallest country in the world. It has been ruled by the Grimaldi dynasty ever since the country was founded in 1297." },
  { name: "Mongol", adjective: "Mongol", graphic_str: "mongolia", legend: "In the centuries after their unification by Chinggis Khan, the Mongols conquered the largest land empire in human history, encompassing most of the continent of Asia. They became notorious for their utter ruthlessness in warfare." },
  { name: "Montenegrin", adjective: "Montenegrin", graphic_str: "montenegro", legend: "Montenegro is a small country on the Balkans, the last to be conquered by the Ottomans and the first to become independent again. Part of Yugoslavia in the 20th century, it dissolved its union with Serbia in 2006." },
  { name: "Moravian", adjective: "Moravian", graphic_str: "moravia", legend: "Great Moravia was a Slavic medieval monarchy whose center was located in the areas of modern Moravia region in Czech Republic. Moravia conquered areas of Bohemia, Slovakia, Pannonia and large parts of southern Poland and Lusatia." },
  { name: "Mordvin", adjective: "Mordvin", graphic_str: "mordovia", legend: "The Mordvins are a Finnic people consisting of two subgroups: the Erzya and the Moksha. Mordvins live mainly in the Republic of Mordovia, a subdivision of the Russian Federation." },
  { name: "Moroccan", adjective: "Moroccan", graphic_str: "morocco", legend: "Modern Morocco gained independence in 1956. However, the area has been inhabited since at least 8000 BCE." },
  { name: "Mozambican", adjective: "Mozambican", graphic_str: "mozambique", legend: "Mozambique is a country in Southeast Africa. It gained independence from Portugal in 1975." },
  { name: "Mughal", adjective: "Mughal", graphic_str: "mughal", legend: "The Mughal Empire ruled most of the Indian subcontinent throughout the early modern era." },
  { name: "Muscovite", adjective: "Muscovite", graphic_str: "moscow", legend: "Moscow emerged as a regional power and successor to the Kievan Rus' in the 12th century CE. Under the Rurikid dynasty, the Muscovites consolidated power through alliances with the Golden Horde and the Orthodox Church, eventually subduing surrounding cities and principalities including the Novgorod Republic." },
  { name: "Muskogee", adjective: "Muskogee", graphic_str: "muskogee", legend: "The Muskogee was a confederacy of North American tribes, including the Creek, Seminole, Choctaw, and Chickasaw. They were based in the area now encompassed by the U." },
  { name: "Mwiska", adjective: "Mwiska", graphic_str: "mwiska", legend: "Comprising five states, variously described as chiefdoms and kingdoms, the Mwiska (a. k." },
  { name: "Namibian", adjective: "Namibian", graphic_str: "namibia", legend: "Although European Powers long neglected the desertic African Southwest, the German Empire established a colony there in the late nineteenth century. After losing World War I, the territory became a mandate under the responsibility of the Union of South Africa." },
  { name: "Nauruan", adjective: "Nauruan", graphic_str: "nauru", legend: "Called Pleasant Island by the European colonizers, Nauru is an island in the South Pacific. The island was first settled by Austronesian peoples around 1000 BCE." },
  { name: "Navajo", adjective: "Navajo", graphic_str: "navajo", legend: "The Navajo or Diné are the most populous Native American nation of the United States. They are closely related to the Apache." },
  { name: "Nazi", adjective: "Nazi", graphic_str: "nazi", legend: "The Nazi regime, under Adolf Hitler's leadership from 1933 to 1945, was a totalitarian dictatorship characterized by extreme nationalism, antisemitism, aggressive militarism, and the systematic persecution and extermination of millions, primarily Jews, through the Holocaust. Germany fell under the control of the Nazi Party in 1933, led by Adolf Hitler." },
  { name: "Neapolitan", adjective: "Neapolitan", graphic_str: "naples", legend: "For centuries the Kingdom of Naples was the largest country on the Italian Peninsula. Many European powers showed interest in the kingdom and its throne changed hands many times." },
  { name: "Nenets", adjective: "Nenets", graphic_str: "nenetsia", legend: "The Nenets are a people living in north-western Russia and the most populous among the Samoyed peoples." },
  { name: "Nepali", adjective: "Nepali", graphic_str: "nepal", legend: "Nepal is a landlocked country located in the Himalayas. Long a multi-cultural and multi-lingual nation, its history is characterized by its location between India and China." },
  { name: "Nestorian", adjective: "Nestorian", graphic_str: "nestoria", legend: "Legends of Prester John circulated in Europe from the 12th through 17th centuries. The stories told of a Nestorian Christian nation beyond the boundaries of the European world; over time the location of the kingdom moved from India to Central Asia to Ethiopia." },
  { name: "New Zealand", adjective: "NewZealand", graphic_str: "newzealand", legend: "The island group of New Zealand was annexed by Britain in 1840. Following a royal proclamation in 1907, the country became an independent dominion within the Commonwealth of Nations." },
  { name: "Newfoundland", adjective: "Newfoundland", graphic_str: "newfoundland", legend: "In precolumbian times Newfoundland and Labrador were settled by the Beothuk, though around 1000 CE for a short time Vikings also settled there. From the late 15th century onward Newfoundland was visited by the Portuguese and English." },
  { name: "Nicaraguan", adjective: "Nicaraguan", graphic_str: "nicaragua", legend: "The largest of the Central American republics, Nicaragua is known for its turbulent history. The country lived through numerous civil wars and foreign interventions until Anastasio Somoza established a notoriously corrupt dictatorship in the 1930s." },
  { name: "Nigerian", adjective: "Nigerian", graphic_str: "nigeria", legend: "Nigeria won full independence from British rule in 1960. It is the most populous country of Africa." },
  { name: "Nigerien", adjective: "Nigerien", graphic_str: "niger", legend: "Niger is a country in the Sahel region of West Africa, named after the Niger river. It achieved independence from France in 1960." },
  { name: "Nimíipuu", adjective: "Nimíipuu", graphic_str: "nez_perce", legend: "The Nimíipuu, or the 'Real People', in their own language, are better known as the 'Nez Percé'. This Native American nation covered parts of Washington, Oregon, Montana and Idaho and consisted of more than 70 permanent villages in 1800." },
  { name: "Norman", adjective: "Norman", graphic_str: "normandy", legend: "After several devastating Viking raids on what is today northern France and a siege of Paris, the Frankish king Charles the Simple granted the Viking leader Rollo a fiefdom in the area. This fief evolved into the Duchy of Normandy, of which the most famous duke is William II \"the Conqueror \" who invaded England in 1066." },
  { name: "North Korean", adjective: "NorthKorean", graphic_str: "north_korea", legend: "In 1945 Korea was split by the Soviet Union and the United States into two states along the 38th parallel, forming North Korea and South Korea. 60 years on, North Korea remains a communist state of the Stalinist type." },
  { name: "Northumbrian", adjective: "Northumbrian", graphic_str: "northumbria", legend: "The Northumbria was a Medieval kingdom of the Angles, in what is now northern England and southern Scotland. It was created after the unification of Bernicia and Deira by king Aethelfrith." },
  { name: "Norwegian", adjective: "Norwegian", graphic_str: "norway", legend: "After centuries of Danish rule, the Norwegians made their own constitution in Eidsvoll, 1814 CE. Finally, in 1905 CE the Norwegians got their independence after a union with Sweden." },
  { name: "Novgorodian", adjective: "Novgorodian", graphic_str: "novgorod", legend: "The Novgorod Republic was was a large Medieval Russian state that stretched from the Baltic Sea to the Ural Mountains. It existed between the 12th and 15th centuries and was centered on the city of Novgorod." },
  { name: "Nubian", adjective: "Nubian", graphic_str: "nubia", legend: "A succession of kingdoms stretching roughly from the 1st to the 6th cataracts of the Nile river in modern Sudan and Egypt, Nubia was ancient Egypt's perennial neighbor, competitor, trading partner, enemy, and source of gold, slaves and soldiers to the south. The border between the two nations fluctuated time and time again." },
  { name: "Numidian", adjective: "Numidian", graphic_str: "numidia", legend: "The Numidians were an ancient Berber people renowned for their horsemanship who were composed of two main tribes in modern Algeria and Tunisia: the Massyli in the east and the Massaesyli in the west. They were united under King Massinissa, whose position was guaranteed by his Roman allies after the 2nd Punic War in which he aided the Romans in their defeat of the Carthaginians." },
  { name: "Nuu-chah-nulth", adjective: "Nuu-chah-nulth", graphic_str: "nuu-chah-nulth", legend: "The Nuu-chah-nulth are a Pacific Northwest people, one of the few Native American peoples to travel in the open ocean and hunt whales. They inhabited most of what is now western Vancouver Island and now number over 8,000 individuals." },
  { name: "Occitan", adjective: "Occitan", graphic_str: "occitania", legend: "Although Occitania never had a real political unity (it consisted of several counties and duchies in today's southern France), its culture enjoyed great prestige all over Europe during the 11th, 12th and 13th centuries, Occitan being the language of troubadours. Its religious freedom allowed the flourishing of Catharism, which was declared heretic by the Pope, and the French kings took advantage of the subsequent crusade to annex its territory." },
  { name: "Ohlone", adjective: "Ohlone", graphic_str: "ohlone", legend: "Gatherers, hunters and fishermen, the Ohlone lived in over 40 bands stretching from the San Francisco Bay south to the Salinas Valley. They spoke eight distinct yet related languages and though they shared many cultural traits common to other Native Californian peoples, the Ohlone were also diverse in some finer aspects of culture." },
  { name: "Old Prussian", adjective: "OldPrussian", graphic_str: "prusai", legend: "The Prussians were Baltic peoples inhabiting the area between the Pomerania, Mazovia, Lithuania and the Baltic Sea (Baltic coast between the lower Vistula and lower Nemen). They were conquered and germanized by the Teutonic Order." },
  { name: "Oldenburgian", adjective: "Oldenburgian", graphic_str: "oldenburg", legend: "Initially a vassal of the dukes of Saxony, Oldenburg became a county directly suzerain to the Holy Roman Emperor in the 12th century. In 1450, when count Christian VI became king Christian I of Denmark, the country entered into a personal union with Denmark." },
  { name: "Omani", adjective: "Omani", graphic_str: "oman", legend: "Oman is an Arab country in southwest Asia on the southeast coast of the Arabian Peninsula. Before the arrival of Islam Oman was controlled by Achaemenids, Parthians and Sassanids." },
  { name: "Ossetian", adjective: "Ossetian", graphic_str: "ossetia", legend: "Modern Ossetians are the successors of the Alans of Ancient history, who fled into the mountains during the Hunnic invasions. Around 800 CE an Alanic kingdom emerged in the Northern Caucasus, which continued to exist until the Mongol invasions." },
  { name: "Ostrogothic", adjective: "Ostrogothic", graphic_str: "valknut", legend: "The Ostrogoths or Greuthungi (meaning people of the steppe, in contrast to the Visigoths-Tervingi, living in the more wooded areas) were an East Germanic people, one of the two tribes of Goths. They conquered Italy from Odoacer and founded their kingdom there." },
  { name: "Otomí", adjective: "Otomí", graphic_str: "otomi", legend: "The Otomí are one of the most ancient peoples of Mexico. They have lived in Central Mexico ever since the development of agriculture or even longer." },
  { name: "Ottoman", adjective: "Ottoman", graphic_str: "ottoman", legend: "In the beginning of the 14th century Osman, a leader of a minor Turkish tribe in western Anatolia, conquered all his neighboring tribes. A century later the Byzantine capital fell to Turkish rule which gave the Ottoman empire access to Europe." },
  { name: "Ozite", adjective: "Ozite", graphic_str: "oz", legend: "The land of Oz was created by L. Frank Baum in 1900 in 'The Wonderful Wizard of Oz' and was subsequently embellished in a number of other books." },
  { name: "P'urhepecha", adjective: "P'urhepecha", graphic_str: "purhepecha", legend: "The P'urhepecha or Tarascans are a people native to the modern Mexican state of Michoacán, the heart of a former empire known to them as Irechikua Ts'intsuntsani, meaning the \"lands of Tzintzuntzan, \" their capital city. Their kings were the perennial enemy of the Aztec empire, who attempted an unsuccessful invasion of the P'urhepecha lands." },
  { name: "Paeonian", adjective: "Paeonian", graphic_str: "paeonia", legend: "The Paeonians were an ancient people that inhabited the areas north of Macedon, between the Thracian and Illyrian tribes. Their language probably had a mixed Thraco-Illyrian origin." },
  { name: "Pakistani", adjective: "Pakistani", graphic_str: "pakistan", legend: "The Federation of Pakistan was formed from the predominantly Muslim regions of British India in 1947." },
  { name: "Palatinate", adjective: "Palatinate", graphic_str: "palatinate", legend: "The Electoral Palatinate was one of the electorates of the Holy Roman Empire, located on the banks of the Rhine. It had a volatile political history, continuously splitting and reuniting." },
  { name: "Palauan", adjective: "Palauan", graphic_str: "palau", legend: "Palaos is a very little country, with only 20000 inhabitants aproximately. It is composed of more than 300 islands of volcanic origin." },
  { name: "Palestinian", adjective: "Palestinian", graphic_str: "palestine", legend: "Palestinians are the Arab inhabitants of the former British mandate of Palestine." },
  { name: "Palmyrene", adjective: "Palmyrene", graphic_str: "palmyra", legend: "Palmyra was a breakaway Roman state in Asia governed by queen Zenobia. In 273 CE Aurelian brought it back under Roman control." },
  { name: "Panamanian", adjective: "Panamanian", graphic_str: "panama", legend: "Located on a narrow isthmus connecting North and South America, Panama is world famous for the Panama canal. Panama declared independence from Colombia in 1903 under US protection." },
  { name: "Papal", adjective: "Papal", graphic_str: "vatican", legend: "The Papal States were the territories on the Italian Peninsula and elsewhere under the direct sovereign rule by the Roman Catholic popes. Established in the 8th century CE from territory donated to the Church by the pious and the wealthy, the Papal States grew to become the dominant power in Italy for centuries." },
  { name: "Papua New Guinean", adjective: "PapuaNewGuinean", graphic_str: "papua_newguinea", legend: "Papua New Guinea is a country occupying the eastern part of the island of New Guinea. Inhabited since time immemorial by Papuan peoples, it was colonized by the British and Germans in the late 19th century." },
  { name: "Papuan", adjective: "Papuan", graphic_str: "west_papua", legend: "The Papuans are the indigenous inhabitants of the island of New Guinea. They are the descendants of the people who first settled the island 40,000 years ago." },
  { name: "Paraguayan", adjective: "Paraguayan", graphic_str: "paraguay", legend: "Paraguay is located in the heartland of South America. It was conquered by the Spanish in the late 16th century." },
  { name: "Parthian", adjective: "Parthian", graphic_str: "parthia", legend: "The Parthians were originally a nomadic people from Central Asia who inhabited the Parthia region of the Seleucid Empire. Under the leadership of the satrap Arsakes they drove the Seleucids from Iran, where they created their own strong empire." },
  { name: "Pashtun", adjective: "Pashtun", graphic_str: "pashtun", legend: "The Pashtuns are an ethnic group that lives mainly in Afghanistan and Pakistan. They speak Pashto, a language closely related to Persian, and live by an age-old code of honor known as Pashtunwali." },
  { name: "Pelasgian", adjective: "Pelasgian", graphic_str: "pelasgian", legend: "Pelasgians or Pelasgoi were an ancient pre-Greek people of Greece. Much is still unknown about them, but it is probable they were of pre-Indo-European origin." },
  { name: "Persian", adjective: "Persian", graphic_str: "iran_ancient", legend: "The first Persian (Achaemenid) Empire lasted from 550 BCE to 330 BCE; the second (Sassanid) from 226 CE to 642 CE." },
  { name: "Peruvian", adjective: "Peruvian", graphic_str: "peru", legend: "Peru was the cradle of the Inca Empire and civilization. It is still today a major center of indigenous South American culture." },
  { name: "Phoenician", adjective: "Phoenician", graphic_str: "phoenicia", legend: "Phoenicia was an ancient civilization, based in what is now the coastal regions of Lebanon and Syria. They spoke a Canaanite language related to Hebrew and were famed mariners." },
  { name: "Phrygian", adjective: "Phrygian", graphic_str: "phrygian", legend: "The Phrygians were an ancient Indo-European people, probably related to the Greeks or Thracians. They arrived in Anatolia around the twelfth century BCE, at the time of the invasion of the Sea Peoples in the Eastern Mediterranean region." },
  { name: "Pictish", adjective: "Pictish", graphic_str: "pict", legend: "The Picts were the indigenous inhabitants of Caledonia, Ancient Scotland. They were probably Celtic or maybe Celticized pre-Indo-Europeans." },
  { name: "Piedmontese", adjective: "Piedmontese", graphic_str: "piedmont", legend: "Piedmont was formed when the Duchy of Savoy elevated itself to the status of a kingdom in 1720. Officially it was a constituent part of the Kingdom of Sardinia-Piedmont." },
  { name: "Pirate", adjective: "Pirate", graphic_str: "pirate", legend: "As long as honest men have sailed the seas, pirates have been a scourge of them and of all coastal dwelling peoples." },
  { name: "Polish", adjective: "Polish", graphic_str: "poland", legend: "The Polish state was formed about a millennium ago, and reached its Golden Age near the end of the 16th century." },
  { name: "Polynesian", adjective: "Polynesian", graphic_str: "polynesian", legend: "Polynesian culture stretches from Hawaii to New Zealand to Easter Island and covers all the islands in between." },
  { name: "Pontic", adjective: "Pontic", graphic_str: "trebizond", legend: "Pontus is a region on the Black Sea coast of Asia Minor, currently part of Turkey but historically part of the Greek cultural realm. A Hellenistic Kingdom of Pontus was founded in the 3rd century BCE, which reached its greatest splendor under Mithridates the Great before succumbing to Rome." },
  { name: "Portuguese", adjective: "Portuguese", graphic_str: "portugal", legend: "Portugal was originally a Leonese county that achieved independence. After finishing it's reconquista in 1249, Portugal founded the first of the great mercantile empires in the early 1400s on the shipbuilding advances funded by Prince Henry the Navigator." },
  { name: "Prussian", adjective: "Prussian", graphic_str: "prussia", legend: "Prussia was originally the name of a pagan Baltic people, who in the 13th century were conquered by the German Teutonic Knight order. The knights established an independent state in this land, and in 1561 Grand Master Albrecht I proclaimed himself hereditary Duke of Prussia." },
  { name: "Puerto Rican", adjective: "PuertoRican", graphic_str: "puerto_rico", legend: "The smallest of the Greater Antilles, Puerto Rico was inhabited by the indigenous Taino people when it was conquered by the Spanish. It was conquered by the United States in 1898, just one year after Spain had granted autonomy to the island." },
  { name: "Qatari", adjective: "Qatari", graphic_str: "qatar", legend: "Qatar is an emirate located on a peninsula on the Persian Gulf. It is one of the wealthiest countries of the world in terms of GDP per capita." },
  { name: "Quebecois", adjective: "Quebecois", graphic_str: "quebec", legend: "Quebec is the largest province of Canada, housing the majority of the Francophone population of America." },
  { name: "Rapa Nui", adjective: "RapaNui", graphic_str: "rapa_nui", legend: "The Rapa Nui are the native Polynesian inhabitants of Easter Island. They have inhabited the island since the end of the first millennium CE." },
  { name: "Rarámuri", adjective: "Rarámuri", graphic_str: "raramuri", legend: "The Rarámuri or Tarahumara live in the canyons of the Sierra Madre Occidental in the north of Mexico. They are well known for their endurance; their traditions include running long distances while kicking wooden balls in races that last up to several days." },
  { name: "Rhenish", adjective: "Rhenish", graphic_str: "rhineland", legend: "The Rhineland was the site of three electorates of the Holy Roman Empire, Cologne, Trier and Mainz, as well as numerous smaller territories. The Rhenish statelets were gradually absorbed by Prussia from the 17th century onwards." },
  { name: "Riffian", adjective: "Riffian", graphic_str: "rif", legend: "The Confederal Republic of the Tribes of the Rif was a short-lived nation founded in September 1921 when Riffians revolted against the Spanish and Moroccans. The country was conquered by the Spanish and French in 1926." },
  { name: "Rio-Grandense", adjective: "Rio-Grandense", graphic_str: "piratini", legend: "The Rio-Grandense Republic or Piratini Republic existed in the Brazilian state of Rio Grande do Sul from 1836 to 1845. It fought the War of Tatters against the Brazilian Imperial Army and was supported by Giuseppe Garibaldi amongst others." },
  { name: "Roman", adjective: "Roman", graphic_str: "rome", legend: "Rome was, in legend, founded by Romulus in 753 BCE. At its height, Rome controlled much of Europe, northern Africa and the Near East." },
  { name: "Romanian", adjective: "Romanian", graphic_str: "romania", legend: "Romania as a nation was formed at the beginning of the 20th century, when the states of Transylvania, Wallachia, and Moldavia merged. It is a country inhabited by people speaking a language reminiscent from the time of ancient Rome." },
  { name: "Romansh", adjective: "Romansh", graphic_str: "grisons", legend: "The Rumantsch or Romansh people are inhabitants of the Swiss canton of Grisons who speak Romansh, a Romance language that retains some unique characteristics and with a rich oral tradition. Although Romansh is one of the four national languages of Switzerland and projects are being undertaken to save the language, it is losing terrain as many of its speakers switch to German." },
  { name: "Russian", adjective: "Russian", graphic_str: "russia", legend: "Russia is the largest country in the world, occupying a huge part of both Europe and Asia. According to legend, Slavic tribes of Novgorod invited the Varangian (Viking) king Oleg to bring order to their land." },
  { name: "Rusyn", adjective: "Rusyn", graphic_str: "rusyn", legend: "The Rusyns are an ethnic group on the western periphery of the East Slavic nations. They live mainly in the Polish-Ukrainian-Slovak borderland and in the Vojvodina." },
  { name: "Rwandan", adjective: "Rwandan", graphic_str: "rwanda", legend: "Rwanda is a hilly and very fertile country in the Great Lakes region of eastern Africa. It supports the densest population of the continent." },
  { name: "Ryukyuan", adjective: "Ryukyuan", graphic_str: "ryukyu", legend: "The Ryukyu Kingdom (1372-1879) was the Land of Propriety, a peaceful maritime trading nation eventually invaded, occupied, and annexed by Japan." },
  { name: "Sabine", adjective: "Sabine", graphic_str: "sabinium", legend: "The Sabines were an Italic tribe whose language was closest to Umbrian. They had an impact on the history of Rome." },
  { name: "Sahrawi", adjective: "Sahrawi", graphic_str: "sadr", legend: "The Sahrawi are the inhabitants of the Western Sahara, a former Spanish colony. Morocco currently controls most of the area, which is considered an illegal occupation by most of the international community." },
  { name: "Saint Lucian", adjective: "SaintLucian", graphic_str: "saint_lucia", legend: "Saint Lucia is an island nation in the Eastern Caribbean. During the colonial era, Saint Lucia changed hands between France and Britain no less than fourteen times until the British finally secured it in 1814." },
  { name: "Saka", adjective: "Saka", graphic_str: "saka", legend: "The Saka were an ancient Iranian tribe from the Central Asian steppes. They were very closely related to the European Scythians, and were probably descendants of the Andronovo culture." },
  { name: "Salishan", adjective: "Salishan", graphic_str: "salish", legend: "The Salishans are a cultural-linguistic group of peoples in the Pacific Northwest region of the United States and Canada. Among the most famous Salishans is Chief Seattle, leader of the Duwamish tribe, after whom the city of Seattle is named." },
  { name: "Salvadoran", adjective: "Salvadoran", graphic_str: "el_salvador", legend: "Originally inhabited by Pipil Indians, in the 16th century El Salvador was conquered by the Spanish. It joined the Central American federation upon independence and became a fully independent republic in 1840." },
  { name: "Sami", adjective: "Sami", graphic_str: "sapmi", legend: "The Sami are a people of northern Scandinavia. Their nation spans over the northernmost regions of the Scandinavian countries and northwestern Russia." },
  { name: "Sammarinese", adjective: "Sammarinese", graphic_str: "san_marino", legend: "San Marino is a tiny landlocked country on the Italian Peninsula. It is the oldest independent republic in the world." },
  { name: "Samnite", adjective: "Samnite", graphic_str: "samnium", legend: "The Samnites were an ancient confederation of Italic tribes who spoke the Oscan language and inhabited Central Italy, South of the Sabines. After losing the wars with Rome the Samnites were subjected to Rome and became Romanized." },
  { name: "Samoan", adjective: "Samoan", graphic_str: "samoa", legend: "Samoa is a country occupying the Western part of the Samoan islands of the Central Pacific; the Eastern part is governed by the United States as American Samoa. Samoa was settled by Austronesian peoples around 1500 BCE." },
  { name: "Samogitian", adjective: "Samogitian", graphic_str: "samogitia", legend: "Samogitia - historical country near the Baltic Sea - home to the last pagans in Europe (official until 1413). Today, Samogitia is a region of Lithuania." },
  { name: "Santomean", adjective: "Santomean", graphic_str: "sao_tome_and_principe", legend: "São Tomé and Príncipe are two islands in the Atlantic Ocean off the coast of Africa. The main island was named after Saint Thomas by the Portuguese sailors who first discovered the island on the saint's feast day around 1470." },
  { name: "Sardinian", adjective: "Sardinian", graphic_str: "sardinia", legend: "Sardinia is an island in the Mediterranean Sea and an autonomous region of Italy. The site of the Nuraghic civilization in prehistory, the island passed to Phoenician and then Roman rule." },
  { name: "Sarmatian", adjective: "Sarmatian", graphic_str: "sarmatia", legend: "The Sarmatians were Iranian pastoral tribes from Central Asia and Southwest Siberia. They were closely related to the Saka and the Scythians." },
  { name: "Saudi", adjective: "Saudi", graphic_str: "saudi_arabia", legend: "Saudi Arabia is located on the Arabian Peninsula and includes Mecca and Medina, the holiest sites of Islam. The First Saudi state was established in 1744." },
  { name: "Savoyard", adjective: "Savoyard", graphic_str: "savoy", legend: "Savoy emerged in the Western Alps after the disintegration of the Burgundian Kingdom. Its dynasty established control over Sardinia and Piedmont and later all of Italy." },
  { name: "Saxon", adjective: "Saxon", graphic_str: "saxony", legend: "The Electorate of Saxony was an independent hereditary electorate of the Holy Roman Empire from 1356-1806." },
  { name: "Scanian", adjective: "Scanian", graphic_str: "scania", legend: "Scania is the southernmost region of Sweden. Historically one of many petty kingdoms in Viking age Scandinavia, it became in medieval times part of Denmark but was ceded to Sweden through the Treaty of Roskilde in 1658." },
  { name: "Schleswig-Holsteinian", adjective: "Schleswig-Holsteinian", graphic_str: "schleswig-holstein", legend: "For much of its history, the duchies of Schleswig and Holstein have been contested by Germany and Denmark. The territories were united in a personal union in 1375." },
  { name: "Scottish", adjective: "Scottish", graphic_str: "scotland", legend: "Scotland, originally settled in late Roman times by Irish raiders who displaced the native Picts, was an independent kingdom from around 1034 CE to the Union of Crowns with England in 1701." },
  { name: "Scottish Gaelic", adjective: "ScottishGaelic", graphic_str: "scottishgaelic", legend: "Both Gaels and the Gaelic language were brought to Scotland by the Dalriada dynasty from Ireland. They first settled in Argyll (Earra Ghaidheal or the Coastland of the Gael) and soon expanded further into territory held by the indigenous Picts and culminating in Kenneth MacAlpin uniting the kingdoms of the Picts and Gaels around 843 CE." },
  { name: "Scythian", adjective: "Scythian", graphic_str: "scythia", legend: "The Scythians or Scyths were an Ancient Iranian people of horse-riding nomadic pastoralists who throughout Classical Antiquity dominated the Pontic-Caspian steppe, known at the time as Scythia. By Late Antiquity the closely-related Sarmatians came to dominate the Scythians in this area." },
  { name: "Seleucid", adjective: "Seleucid", graphic_str: "seleucid", legend: "The Seleucid Empire was one of the diadochi states founded when Alexander the Great's generals carved up his empire after his death. It was named after its founder Seleucus I Nicator." },
  { name: "Seljuk", adjective: "Seljuk", graphic_str: "seljuk", legend: "The Seljuks were a Turkic horde whose name comes from their founder Seljuk. After the victory over the Ghaznavids in 1040 CE they created their own state." },
  { name: "Seminole", adjective: "Seminole", graphic_str: "seminole", legend: "The Seminole people emerged in the 18th century through a process of ethnogenesis, out of groups of lower Creek emigrants who fled the encroachment of White settlers in the U. S." },
  { name: "Senegalese", adjective: "Senegalese", graphic_str: "senegal", legend: "Senegal is the westernmost country of mainland Africa. It has been independent from France since 1960." },
  { name: "Serbian", adjective: "Serbian", graphic_str: "serbia", legend: "Serbia is part of the region of the Southern Slavs that was conquered by the Ottomans after the collapse of the Byzantine Empire. During most of the 20th century it was part of the Yugoslav Federation." },
  { name: "Seychellois", adjective: "Seychellois", graphic_str: "seychelles", legend: "The Seychelles is an archipelagic country off the coast of Eastern Africa in the Indian Ocean. The Islands have been visited by Austronesian, Maldivian and Arab merchants in antiquity but by the time of the European discoveries the Seychelles had no indigenous population." },
  { name: "Shan", adjective: "Shan", graphic_str: "shan", legend: "The Shans are an ethnic group related to the Thais and the Laotians. After the fall of the Burmese dominated Bagan Kingdom to the Mongols in 1287, a succession of Shan kingdoms known by historians as the Shan States controlled much of today's Myanmar, Laos, Thailand, as well as China's Yunnan Province." },
  { name: "Shawnee", adjective: "Shawnee", graphic_str: "shawnee", legend: "An Algonquian people, the Shawnee were led by Tikamthi (better known as Tecumseh) and his brother Tenskwatawa in trying to create a pan-native alliance against American expansionism but were ultimately unsuccessful and made to resettle in the Indian Territory (modern Oklahoma)." },
  { name: "Sherpa", adjective: "Sherpa", graphic_str: "sherpa", legend: "Sherpas are an ethnic group who settled in the Himalaya region of modern-day Nepal in the 15th century. They are of Tibetan stock and speak a language related to modern Tibetan though they are not mutually intelligible." },
  { name: "Siberian", adjective: "Siberian", graphic_str: "siberia", legend: "Siberia is a historical and geographical region of Russia and the USSR. During the reign of the czars separatist sentiments prevailed amongst some Slavic colonists." },
  { name: "Sicilian", adjective: "Sicilian", graphic_str: "sicily", legend: "Sicily is the largest island of Italy. It has been ruled by Greeks, Carthaginians, Romans, Vandals, Ostrogoths, Byzantines and Arabs." },
  { name: "Sierra Leonean", adjective: "SierraLeonean", graphic_str: "sierra_leone", legend: "Sierra Leone is a country in West Africa. It was founded in 1792 as a home for liberated slaves and quickly passed to become a British dependency." },
  { name: "Sikh", adjective: "Sikh", graphic_str: "sikh", legend: "Sikhs are the followers of a monotheistic religion originating from the Indian Subcontinent in the 15th century. The Punjab, on the border of Pakistan and India, is the heartland of Sikhism." },
  { name: "Sikkimese", adjective: "Sikkimese", graphic_str: "sikkim", legend: "Wedged between Nepal and Bhutan, the Himalayan kingdom of Sikkim was ruled by a lineage of monarchs known as chogyals for centuries, until becoming the 22nd state of India in 1975." },
  { name: "Silesian", adjective: "Silesian", graphic_str: "silesia", legend: "Silesia is a region of southern Poland that was at one time an independent kingdom." },
  { name: "Singaporean", adjective: "Singaporean", graphic_str: "singapore", legend: "Singapore is a mercantile city-state located at the southernmost tip of the Malaysian Peninsula." },
  { name: "Sinhalese", adjective: "Sinhalese", graphic_str: "sinhalese", legend: "The Sinhalese people of Sri Lanka trace their ancestry to the semi-legendary Prince Vijaya who settled the island of Sri Lanka together with 700 followers in 543 BCE." },
  { name: "Sioux", adjective: "Sioux", graphic_str: "cheyenne", legend: "The Sioux was a North American nation that fought several decisive battles against the United States. It consisted of three distinct groups of tribes: the Lakota, the Dakota and the Nakota." },
  { name: "Slavic", adjective: "Slavic", graphic_str: "slavic", legend: "The Slavs are a modern linguistic group of several nations in Eastern Europe with common historical roots. The origin of the Slavs is not known precisely, therefore there are many hypotheses trying to explain them." },
  { name: "Slovakian", adjective: "Slovakian", graphic_str: "slovakia", legend: "Slovakia is a country in the heart of Europe. Formerly part of Czechoslovakia, until 1918 it was part of the Austro-Hungarian Empire." },
  { name: "Slovenian", adjective: "Slovenian", graphic_str: "slovenia", legend: "Slovenia was the most western and northern republic of the old Yugoslav Federation." },
  { name: "Solomon Islander", adjective: "SolomonIslander", graphic_str: "solomon_islands", legend: "Solomon Islands is a country in Melanesia, located between Papua New Guinea and Vanuatu. Inhabited by Austronesian peoples since 4000 BCE, the islands became a British protectorate in the 19th century." },
  { name: "Somali", adjective: "Somali", graphic_str: "somalia", legend: "Somalia is a country in the Horn of Africa. In ancient times Somalia was a trading hub." },
  { name: "Somaliland", adjective: "Somaliland", graphic_str: "somaliland", legend: "The Republic of Somaliland is an unrecognized state in Northern Somalia, roughly concurrent with former British Somaliland. It declared independence upon the collapse of Somalia in 1991." },
  { name: "Songhai", adjective: "Songhai", graphic_str: "songhai", legend: "The Songhai people established a state in the 11th century CE centered on the city of Gao. Following the decline of the Mali empire a few hundred years later, the Songhai established an empire of their own which eventually grew to become one of the largest in the history of Africa." },
  { name: "Sorbian", adjective: "Sorbian", graphic_str: "lusatia", legend: "The Sorbs are West Slavic people living in the East of Germany in Eastern Saxony and Southern Brandenburg (Lusatia). The region has historically been associated with Poland and Bohemia." },
  { name: "Sotho", adjective: "Sotho", graphic_str: "lesotho_old", legend: "A Bantu people in Southern Africa, the ancestors of the Basotho first arrived in the region by the end of the first millennium CE. The Basotho first formed a unified polity in the early 19th century under king Moshoeshoe I." },
  { name: "South African", adjective: "SouthAfrican", graphic_str: "south_africa", legend: "Dutch settlers began colonizing southern Africa in the 17th century. After many wars between primarily Boers (descendants of Dutch settlers), British forces and Zulus, the Union of South Africa was created in 1910." },
  { name: "South American", adjective: "SouthAmerican", graphic_str: "unasur", legend: "The Union of South American Nations was formed in 2008, modeled after the European Union, but panamericanism has already existed since the 19th century." },
  { name: "South Korean", adjective: "SouthKorean", graphic_str: "korea", legend: "Formerly the site of a unified Korean state, the Korean peninsula is today divided into two states - North and South Korea - as a result of the stalemate after the Korean War in 1953. The South Korean government was formed from the nationalist and anti-communist \"Provisional Government of the Republic of Korea \" in 1948." },
  { name: "South Sudanese", adjective: "SouthSudanese", graphic_str: "southern_sudan", legend: "A long civil war pitted Southern Sudan, inhabited mostly by black Africans and predominantly Animist and Christian, against the Muslim and Arab North. The war left two million dead and many more displaced until a ceasefire was signed in 2005." },
  { name: "South Vietnamese", adjective: "SouthVietnamese", graphic_str: "rvn", legend: "South Vietnam, officially the Republic of Vietnam, was the American-backed state during the Vietnam War. The country was reunited with North Vietnam after it was conquered by communist forces in 1975." },
  { name: "South Yemeni", adjective: "SouthYemeni", graphic_str: "south_yemen", legend: "The area around Aden was colonized by the British in 1839. South Yemen declared independence in 1967 and joined the communist bloc." },
  { name: "Soviet", adjective: "Soviet", graphic_str: "soviet", legend: "The history of the Soviet Union starts in November 1917, when under Lenin's leadership a Bolshevik revolution occurred. On December 31 1922, four Soviet republics integrated into one country." },
  { name: "Spanish", adjective: "Spanish", graphic_str: "spain", legend: "The modern Spanish nation was formed when the rulers of the kingdoms of Castile and Aragon led the recapture of the Iberian peninsula from the Moslems. The Reconquista was completed in 1492, the same year Columbus sailed." },
  { name: "Sri Vijaya", adjective: "SriVijaya", graphic_str: "srivijaya", legend: "Sri Vijaya was an empire centered on Palembang in eastern Sumatra and extended its control through much of the coastal regions of Sumatra, Java, Borneo and the Malay peninsula. It was founded sometime in the 3rd century CE and lasted until roughly 1400, falling first to Jambi, then to Singhasari and other regional powers, including the South Indian Chola dynasty." },
  { name: "Sudanese", adjective: "Sudanese", graphic_str: "sudan", legend: "In 1820 Sudan came under Egyptian rule and later British rule. Sudan became independent in 1956." },
  { name: "Suebian", adjective: "Suebian", graphic_str: "suebian", legend: "The Suebians were an ancient West Germanic tribal confederation, which may have been formed by Ariovistus for his expedition to Gaul. The Suebians included the Germanic tribes from the Elbe river basin belonging to the Herminonic language group, such as the Marcomanni and Quadi." },
  { name: "Sumerian", adjective: "Sumerian", graphic_str: "sumeria", legend: "Sumer controlled southern Mesopotamia until the rise of Babylonia. Tablets of Sumerian writing some 5500 years old have been found, pre-dating every other writing in history." },
  { name: "Surinamese", adjective: "Surinamese", graphic_str: "suriname", legend: "Suriname is the smallest independent country of South America. Originally it was inhabited by Arawak Indians." },
  { name: "Swahili", adjective: "Swahili", graphic_str: "swahili", legend: "The Swahili are a Bantu ethnic group living along the Eastern Coast of Africa. From about the 9th century onwards the region, at the crossroads of Islamic and African cultural influences, saw the rise of Swahili city states, including Zanzibar, Kilwa Kisiwani, Mozambique and Sofala." },
  { name: "Swazi", adjective: "Swazi", graphic_str: "swaziland", legend: "The Swazi are a Bantu people of southern Africa. Under the leadership of Mswati II (1820 - 1868), the Swazis expanded their territory and stabilized the southern frontier with the Zulus." },
  { name: "Swedish", adjective: "Swedish", graphic_str: "sweden", legend: "The Kingdom of Sweden was christianized and consolidated as a political entity by the 12th century CE. The country rose to prominence as one of the great powers of Europe in the 17th century, following substantial military conquests by the so called Warrior Kings." },
  { name: "Swiss", adjective: "Swiss", graphic_str: "switzerland", legend: "Switzerland has existed as a state in its present form since the adoption of the Swiss Federal Constitution in 1848. The precursors of modern Switzerland established a protective alliance at the end of the 13th century, forming a loose confederation of states which persisted for centuries." },
  { name: "Syrian", adjective: "Syrian", graphic_str: "syria", legend: "The modern Syrian Arab Republic was formed from a French mandate and gradually gained independence during the 1940s." },
  { name: "Tahitian", adjective: "Tahitian", graphic_str: "french_polynesia", legend: "The islands of what is now French Polynesia were first settled by Polynesian peoples in the 3rd century CE. France established a protectorate over Tahiti, the main island of the archipelago, in 1842." },
  { name: "Taino", adjective: "Taino", graphic_str: "taino", legend: "Native inhabitants of the Bahamas, Cuba, Hispaniola, Puerto Rico, Jamaica, and other Caribbean islands who gave us the root words for hurricane, tobacco, potato, canoe, barbeque, hammock, and yucca. They were a matrilineal people, and the first that Columbus came into contact with in 1492." },
  { name: "Tairona", adjective: "Tairona", graphic_str: "tairona", legend: "A Chibchan-speaking people related to the Kuna of Panama and the Muisca of central Colombia, the Tairona inhabit the modern Magdalena and La Guajira Departments of northern Colombia. Their city of Teyuna was founded sometime around 500 BCE." },
  { name: "Taiwanese", adjective: "Taiwanese", graphic_str: "taiwan", legend: "The Republic of China was established in 1912 as the successor state of the Qing Empire, ending over two millennia of imperial rule in China. When the Chinese Nationalists who ruled the Republic lost a civil war against the Chinese Communists in 1949, the Nationalist government evacuated to the island of Taiwan, establishing Taipei as the provisional capital of the Republic of China." },
  { name: "Tajik", adjective: "Tajik", graphic_str: "tajikistan", legend: "Tajikistan is a nation in Central Asia. The Tajiks trace the foundation of their nation back to the Samanid Empire, one of the first Persian states to appear after the Arab conquest." },
  { name: "Tanganyikan", adjective: "Tanganyikan", graphic_str: "tanganyika", legend: "Inhabited by Bantu tribes since the beginning of the Common Era, Tanganyika became a German colony in the late 19th century. It was conquered by the British during World War I and declared independence in 1961." },
  { name: "Tanzanian", adjective: "Tanzanian", graphic_str: "tanzania", legend: "Tanzania was formed as a merger of the former British colonies of Tanganyika and Zanzibar in 1964. For two decades the country was ruled by Julius Nyerere, who followed the tenets of African socialism." },
  { name: "Tatar", adjective: "Tatar", graphic_str: "tatarstan", legend: "The Tatars are a Turkic-speaking nation. Various Tatar states existed in the Middle Ages: Kazan, Crimea, Astrakhan, Sibir and other khanates." },
  { name: "Teutonic", adjective: "Teutonic", graphic_str: "teutonic_order", legend: "The Teutonic Order led a series of crusades against pagan Balts during the High Middle Ages. In 1224 it founded the 'Ordenstaat' or State of the Order, which remained a powerful country for three centuries." },
  { name: "Texan", adjective: "Texan", graphic_str: "texas", legend: "Texas, \"the Lone Star State \" is the second largest and second most populous state of the USA, famous for its \"larger than life \" cowboy culture and Mexican heritage. After the famous Battle of the Alamo, The Texians defeated the Mexicans at San Jacinto and declared independence." },
  { name: "Thai", adjective: "Thai", graphic_str: "thailand", legend: "The Thai kingdom was the only country in Southeast Asia to preserve its independence through the colonial era of the 18th and 19th centuries CE." },
  { name: "Thracian", adjective: "Thracian", graphic_str: "thrace", legend: "The second most numerous people in the ancient western world." },
  { name: "Thuringian", adjective: "Thuringian", graphic_str: "thuringia", legend: "The Thuringians were an ancient Germanic confederation in what is now Central Germany, established after the defeat of the Huns. Defeated by the Franks in the 8th century, Thuringia later became a landgraviate of the Holy Roman Empire." },
  { name: "Tibetan", adjective: "Tibetan", graphic_str: "tibet", legend: "The Tibetan homeland is sometimes called the \"Roof of the World \", the highest elevated region in the world. In the 7th century, Tibet emerged as a formidable empire under the leadership of king Songtsen Gampo, being recognized by both China and India." },
  { name: "Timurid", adjective: "Timurid", graphic_str: "timur", legend: "Timur was a military genius who claimed lineage from Chinggis Khan and from his capital in Samarkand conquered all of Central Asia as well as parts of the Middle East and India. The court culture of Timurid Empire was heavily Persianized, while the imperial administration and military organization displayed influences from the Timurid ruling elite's Mongolian and Turkic origins." },
  { name: "Tocharian", adjective: "Tocharian", graphic_str: "tocharian", legend: "The Tocharians were an Indo-European people living in what is now Xinjiang in western China. Because of their unique geopolitical position, their kingdoms of Shanshan, Kucha, and Khotan (as well as other, smaller ones) were influenced by Chinese, Persian, Indian, Sogdian, Scythian, and Tibetan cultures." },
  { name: "Togolese", adjective: "Togolese", graphic_str: "togo", legend: "Togo became a German protectorate in 1885 and was conquered by the French and British in World War II. Togo became independent in 1960." },
  { name: "Toltec", adjective: "Toltec", graphic_str: "toltec", legend: "The Toltecs were a Meso-American civilization that existed from the 10th to the 12th century. The Toltec Empire was founded by Ce Tecpatl Mixcoatl, who led his nomadic people from the north to settle on the Mexican High Plain." },
  { name: "Tongan", adjective: "Tongan", graphic_str: "tonga", legend: "An island group in the Southern Pacific, Tonga was settled by Polynesians around 1000 BCE. Although the islands became a British protectorate in the 19th century, they are the only country in Oceania to have escaped actual colonization." },
  { name: "Transnistrian", adjective: "Transnistrian", graphic_str: "transnistria", legend: "Transnistria was added to the Moldavian SSR by Stalin, although it was mostly inhabited by Russians and Ukrainians. After the collapse of the Soviet Union Transnistria declared its independence from Moldova." },
  { name: "Transylvanian", adjective: "Transylvanian", graphic_str: "transylvania", legend: "Transylvania is a historical territory in what is now Romania, inhabited by Romanians, Hungarians and Saxon Germans. Transylvania became a principality under nominal Hungarian suzereignty when that country started to crumble under the Ottoman incursions." },
  { name: "Trinidadian and Tobagonian", adjective: "TrinidadianandTobagonian", graphic_str: "trinidad_and_tobago", legend: "Trinidad and Tobago is a country in the Caribbean, consisting of the two eponymous islands. It is the most populous country of the Lesser Antilles." },
  { name: "Tswana", adjective: "Tswana", graphic_str: "bophuthatswana", legend: "The Batswana are a Bantu people in Southern Africa. With about 20% of the population they are the dominant ethnicity of Botswana, which is named after them." },
  { name: "Tuareg", adjective: "Tuareg", graphic_str: "tuareg", legend: "The Tuareg or Imuhagh are a pastoralist nomadic Berber people inhabiting the interior of the Sahara Desert, mostly in Algeria, Niger and Mali. Despite their matrilineal organization they are followers of Islam." },
  { name: "Tunisian", adjective: "Tunisian", graphic_str: "tunisia", legend: "The Phoenicians founded Carthage in the area where Tunisia is today. Carthage later became a major power in the Mediterranean region until it was defeated by the Romans in 146 BCE." },
  { name: "Tupi", adjective: "Tupi", graphic_str: "tupi", legend: "The Tupi are a native Brazilian people related to the Guarani who inhabited the modern Brazilian states of Paraiba, Pernambuco, Ceara, Rio Grande do Norte, Alagoas, Sergipe and others as well. Their chiefdoms were destroyed through Portuguese slave-raids, the creation of mission-villages, and disease." },
  { name: "Turkish", adjective: "Turkish", graphic_str: "turkey", legend: "Modern Turkey is the successor state of the Ottoman Empire, which collapsed and was dismembered by the victors in World War I after backing the Central Powers. The country was subsequently reformed and secularized by Kemal Mustapha, the hero of the defense of Gallipoli." },
  { name: "Turkish Cypriot", adjective: "TurkishCypriot", graphic_str: "trnc", legend: "Turks first settled in Cyprus after the Ottomans conquered the island in 1571. Political unrest and ethnic tensions between Turkish and Greek Cypriots led to an invasion by the Turkish military in 1974, followed by the declaration of independence of the Turkish Republic of North Cyprus in 1983." },
  { name: "Turkmen", adjective: "Turkmen", graphic_str: "turkmenistan", legend: "Turkmen tribes were first united in the 11th century CE under Togrul Beg, second ruler of the Seljuk Empire. As the Seljuk state broke down under the pressure from encroaching Mongols, the Turkmens started a westward migration." },
  { name: "Tuvan", adjective: "Tuvan", graphic_str: "tannu_tuva", legend: "Tuvans are a Turkic people living in the Autonomous Republic of Tuva in the south of Siberia. Tuva split off from China in 1921 and then formed the independent republic of Tannu Tuva allied with the Soviet Union." },
  { name: "Tyrolian", adjective: "Tyrolian", graphic_str: "tyrol", legend: "Tyrol was a county in the Alps. In the 16th century its own dynasty died out and the region passed to Habsburg Austria." },
  { name: "Ugandan", adjective: "Ugandan", graphic_str: "uganda", legend: "The Republic of Uganda is located in eastern Africa. The country contains part of Lake Victoria, which is also in Kenya and Tanzania." },
  { name: "Ukrainian", adjective: "Ukrainian", graphic_str: "ukraine", legend: "Ukraine is a vast region on the westernmost marches of the former Soviet Union. It includes some of the most fertile black-soil cropland on Earth." },
  { name: "UN", adjective: "UN", graphic_str: "united_nations", legend: "The United Nations believe in human rights and the protection of the weak." },
  { name: "Urartian", adjective: "Urartian", graphic_str: "urartu", legend: "Urartu was an ancient Hurrian state located around Lake Van in the eastern part of Anatolia. The earliest historical mention of Urartu comes from texts of the Assyrian king Shalmaneser I dating from the 13th century BCE." },
  { name: "Uruguayan", adjective: "Uruguayan", graphic_str: "uruguay", legend: "Uruguay, a small South American country sometimes referred to as \"Switzerland of the Americas \" due to its once highly developed social welfare system." },
  { name: "Uyghur", adjective: "Uyghur", graphic_str: "uyghur", legend: "Uyghur was an east Turk empire and civilization. At its height in 820 CE it controlled most of Central and North Asia." },
  { name: "Uzbek", adjective: "Uzbek", graphic_str: "uzbekistan", legend: "The Central Asian nation of Uzbekistan has been the site of many ancient states such as Khwarezm, the Khanate of Bukhara, and the Khanate of Kokand. The Uzbeks regard themselves as descendants of Timur, founder of the Timurid dynasty, who ruled from his capital at Samarkand." },
  { name: "Vampire", adjective: "Vampire", graphic_str: "vampire", legend: "Bloodsucking creatures of legend." },
  { name: "Vandalic", adjective: "Vandalic", graphic_str: "vandal", legend: "The Vandals were an East Germanic people originating from what is now Southern Poland and Slovakia. They entered the Roman Empire in the early 5th century CE." },
  { name: "Vanuatuan", adjective: "Vanuatuan", graphic_str: "vanuatu", legend: "Vanuatu, formerly known as the New Hebrides, is a country in Melanesia, consisting of about 80 islands. First inhabited by Melanesians, the islands were contested by the British and French in the late 19th century." },
  { name: "Vedic", adjective: "Vedic", graphic_str: "vedic", legend: "The cradle of Ancient Indian civilization lay in the Indus river valley in modern-day Pakistan." },
  { name: "Veletian", adjective: "Veletian", graphic_str: "veletian", legend: "The Veletians or Lutici were a medieval West Lechitic tribal confederation in what is nowadays the northeastern part of Germany (Brandenburg and Mecklenburg). Their tribes were of mixed Slavic and Germanic origin, which was visible in their language." },
  { name: "Venda", adjective: "Venda", graphic_str: "venda", legend: "The Vhavenda are a Bantu people in South Africa and Zimbabwe. Once the rulers of the Mapungubwe Kingdom, they now count about one million members, mostly in the province of Limpopo." },
  { name: "Venetian", adjective: "Venetian", graphic_str: "venice", legend: "The Republic of Venice emerged from the shadows of history when refugees from barbarian marauders gathered on the safety of the islands of a lagoon in northeast Italy. Originally a loyal subject of the Eastern Roman empire, it gradually acquired its independence and ranked among the superpowers of the Middle Ages." },
  { name: "Venetic", adjective: "Venetic", graphic_str: "venetic", legend: "The Veneti were an ancient Indo-European people who inhabited an area roughly coinciding with the modern Italian region of Veneto. Their language is of unknown origin, but probably from Central Europe, because it shares some features with Celtic and Germanic languages." },
  { name: "Venezuelan", adjective: "Venezuelan", graphic_str: "venezuela", legend: "Venezuela is the northernmost country in South America. Having been a Spanish colony since the 16th century, the country gained independence on July 5th 1811 under the leadership of El Libertador Simón Bolivar - The Liberator." },
  { name: "Vermont", adjective: "Vermont", graphic_str: "vermont", legend: "Vermont was an independent state for 14 years before it joined the United States in 1791. Currently it is one of the smallest states of the United States, both in population and area." },
  { name: "Vietnamese", adjective: "Vietnamese", graphic_str: "vietnam", legend: "The Vietnamese nation was founded in the first century CE by twin sisters who became the war leaders of a revolt against a Chinese military governor." },
  { name: "Viking", adjective: "Viking", graphic_str: "viking", legend: "The Vikings raided and traded along the coasts of Europe between 800 CE and 1100 CE. Viking raiders eventually became the rulers of Normandy, Russia, and a short-lived kingdom in Sicily." },
  { name: "Vincentian", adjective: "Vincentian", graphic_str: "svg", legend: "Saint Vincent and the Grenadines were amongst the last Caribbean islands to be colonized, as local Carib Indians intermarried with runaway slaves and fought off European colonizers. In the 18th century the islands were contested by the French and British." },
  { name: "Visigothic", adjective: "Visigothic", graphic_str: "visigoth", legend: "The Thervingi or Visigoths were an East Germanic people, one of the two tribes of the Goths. They probably originated from Scandinavia." },
  { name: "Vistulan", adjective: "Vistulan", graphic_str: "vistulan", legend: "Vistulans were a West Slavic tribe inhabiting what is today the area of Lesser Poland. Little is known about their history." },
  { name: "Volapükan", adjective: "Volapükan", graphic_str: "volapuk", legend: "Volapük is an international auxiliary language constructed by the German priest Johann Martin Schleyer in 1879. It enjoyed a brief popularity in the late 19th century." },
  { name: "Volga Bulgar", adjective: "VolgaBulgar", graphic_str: "volga_bulgar", legend: "The Volga Bulgars were Medieval Turkic people inhabiting the middle Volga region. They may have been descendants of European Huns who migrated from the Ukrainian Steppe to the North." },
  { name: "Volga German", adjective: "VolgaGerman", graphic_str: "volga_german", legend: "The Volga Germans were ethnic Germans who lived along the River Volga in Southern Russia, around the city of Saratov and to the South. They were recruited as immigrants in the 18th century." },
  { name: "Walloon", adjective: "Walloon", graphic_str: "wallonia", legend: "The Walloons are the French speaking inhabitants of Belgium. In the 19th century, Wallonia was first region on the European continent to industrialize and the second in the world after England." },
  { name: "Welsh", adjective: "Welsh", graphic_str: "wales", legend: "The Welsh at one time controlled all of what is now England until being driven into the mountainous western reaches by invading Saxons." },
  { name: "West Indian", adjective: "WestIndian", graphic_str: "west_indies_federation", legend: "The West Indies, known for pirates, rum, cricket and beaches. The British West Indies formed the short-lived West Indies Federation in 1958." },
  { name: "Western Pomeranian", adjective: "WesternPomeranian", graphic_str: "pomerania", legend: "Western Pomerania is a geographical and historical region in North West Poland and the extreme North East of Germany. Initially an independent Slavic state, Western Pomerania was twice conquered by the Polish." },
  { name: "Western Roman", adjective: "WesternRoman", graphic_str: "labarum", legend: "The Roman Empire was first divided by Diocletian in 286 and split for good upon Theodosius' death in 395. Unlike its Eastern counterpart, the Byzantine empire, the Western Roman Empire was not capable of resisting barbarian invasions and economic disintegration." },
  { name: "Westphalian", adjective: "Westphalian", graphic_str: "westphalia", legend: "Westphalia, before becoming a Prussian province, was the western region of the Duchy of Saxony. Today it makes up the northern part of the largest German federal state, North Rhine-Westphalia." },
  { name: "Wuerttembergian", adjective: "Wuerttembergian", graphic_str: "wuerttemberg", legend: "Wuerttemberg was a country in Swabia, in southwestern Germany. After World War II it was merged with Baden and Hohenzollern to form the land of Baden-Wuerttemberg." },
  { name: "Xhosa", adjective: "Xhosa", graphic_str: "xhosa", legend: "The Xhosa are Bantu people in South Africa, having arrived there from the Great Lakes region by the 17th century. During the apartheid era there were two Xhosa Bantustans, Transkei and Ciskei." },
  { name: "Xiongnu", adjective: "Xiongnu", graphic_str: "xiongnu", legend: "The Xiongnu, also known as Asiatic Huns, were an ancient tribal confederation of mixed origin. Their language is unknown; it may have belonged to the Altaic or Yeniseian language family." },
  { name: "Yakut", adjective: "Yakut", graphic_str: "sakha", legend: "Oral tradition indicates that the Yakuts - or Sakha as they call themselves - migrated north from the Central Asian steppes to the shores of Lake Baikal in the 10th century CE. They intermarried with the native population and established a nation along the Lena river, having diplomatic relations with at least the Chinese, the Mongols, and the various Turkic peoples of the region." },
  { name: "Yemeni", adjective: "Yemeni", graphic_str: "yemen", legend: "Yemen is the only republic on the Arabian Peninsula. Although it was the site of several ancient civilizations, Yemen only exists in its current form since North Yemen annexed South Yemen in 1990." },
  { name: "Yucatecan", adjective: "Yucatecan", graphic_str: "yucatan", legend: "Yucatán is a peninsula of Mexico, famous for its Maya heritage and its white beaches. Its name is often claimed to mean \"we don't understand you \" in Yucatec Maya." },
  { name: "Yugoslav", adjective: "Yugoslav", graphic_str: "yugoslavia", legend: "Yugoslavia was a state consisting of the Slavic nations of the western Balkans. It was a kingdom until 1941, when it was occupied by the Axis powers." },
  { name: "Zambian", adjective: "Zambian", graphic_str: "zambia", legend: "Zambia was inhabited by Bantu peoples when it was colonized by the British in the 19th century. Governed as Northern Rhodesia by the British, Zambia gained its independence in 1964." },
  { name: "Zanzibari", adjective: "Zanzibari", graphic_str: "zanzibar", legend: "An archipelago off the coast of Eastern Africa, Zanzibar has been an international trading center since time immemorial. Zanzibari traders controlled much of the spice and slave trade in the western part of the Indian Ocean." },
  { name: "Zapotec", adjective: "Zapotec", graphic_str: "zapotec", legend: "The Zapotecs or Binnizá live in the Mexican state of Oaxaca. They formed one of the oldest and most resilient Mesoamerican civilizations." },
  { name: "Zhuang", adjective: "Zhuang", graphic_str: "zhuang", legend: "The Zhuang people live in far southwestern China, an ancient border region that has long separated Sinitic civilization from the aboriginal peoples of Southeast Asia. Known for their unique irrigation and scenic terraced rice paddies, they were under pressure from various Chinese dynasties for most of the Ancient era." },
  { name: "Zimbabwean", adjective: "Zimbabwean", graphic_str: "zimbabwe", legend: "Zimbabwe is a country in Southern Africa, named after the old Zimbabwe kingdom. It became a British colony called South Rhodesia in 1898." },
  { name: "Zulu", adjective: "Zulu", graphic_str: "zulu", legend: "The Zulus are a warlike Bantu people who migrated from west-central Africa into southern Africa beginning in the early 1700s, conquering the native Khoisan peoples and clashing with European settlers." }
];
